/* !!! ULTRA-STRIKTNÉ BEZPEČNOSTNÉ PRAVIDLO !!!
   1. VYTVORENIE NOVÉHO SÚBORU: Vytvor súbor 'src/context/DataContext.tsx'.
   2. ŽIADNE ZMENY V EXISTUJÚCICH SÚBOROCH: Tento krok sa nedotkne App.tsx ani iných komponentov.
   3. CIEĽ: Pripraviť React Context, ktorý bude obaľovať existujúci hook useFirestoreData.
*/

// SÚBOR: src/context/DataContext.tsx

import React, { createContext, useContext, ReactNode } from 'react';
import { useFirestoreData } from '../hooks/useFirestoreData';
import { 
  Task, UserData, DBItem, MapSector, PartRequest, 
  BOMRequest, BreakSchedule, SystemBreak, BOMComponent 
} from '../types/appTypes';

// Definícia typu dát, ktoré kontext poskytuje (kopíruje výstup z useFirestoreData)
interface DataContextType {
  tasks: Task[];
  users: UserData[];
  partsMap: Record<string, string>;
  bomMap: Record<string, BOMComponent[]>;
  workplaces: DBItem[];
  missingReasons: DBItem[];
  logisticsOperations: DBItem[];
  mapSectors: MapSector[];
  partRequests: PartRequest[];
  bomRequests: BOMRequest[];
  breakSchedules: BreakSchedule[];
  systemBreaks: SystemBreak[];
  isBreakActive: boolean;
  activeBreak: SystemBreak | null;
}

const DataContext = createContext<DataContextType | undefined>(undefined);

interface DataProviderProps {
  children: ReactNode;
  isAuthenticated: boolean;
  currentUserRole: string;
}

export const DataProvider: React.FC<DataProviderProps> = ({ 
  children, 
  isAuthenticated, 
  currentUserRole 
}) => {
  // Používame existujúci hook, ktorý už máš otestovaný
  const data = useFirestoreData(isAuthenticated, currentUserRole);

  return (
    <DataContext.Provider value={data}>
      {children}
    </DataContext.Provider>
  );
};

// Vlastný hook pre jednoduché použitie v komponentoch
export const useData = () => {
  const context = useContext(DataContext);
  if (context === undefined) {
    throw new Error('useData must be used within a DataProvider');
  }
  return context;
};

