import React, { useState } from 'react';
import { db } from '../../firebase';
import { doc, getDoc, writeBatch } from 'firebase/firestore';
import { useLanguage } from '../LanguageContext';

interface MasterDbSyncModalProps {
    isOpen: boolean;
    onClose: () => void;
    onSyncSuccess: (count: number) => void;
}

const MasterDbSyncModal: React.FC<MasterDbSyncModalProps> = ({ isOpen, onClose, onSyncSuccess }) => {
    const { t, language } = useLanguage();
    const [password, setPassword] = useState('');
    const [status, setStatus] = useState<'idle' | 'connecting' | 'preview' | 'importing'>('idle');
    const [newParts, setNewParts] = useState<{p: string, d: string}[]>([]);

    if (!isOpen) return null;

    const handleConnect = async () => {
        setStatus('connecting');
        try {
            // Simulácia pripojenia k externému zdroju (chránený master dokument)
            const masterRef = doc(db, 'settings', 'master_catalog');
            const snap = await getDoc(masterRef);

            if (!snap.exists()) {
                alert(t('db_sync_error_fetch'));
                setStatus('idle');
                return;
            }

            const data = snap.data();
            if (data.accessKey !== password) {
                alert(t('db_sync_error_pass'));
                setStatus('idle');
                return;
            }

            setNewParts(data.parts || []);
            setStatus('preview');
        } catch (e) {
            alert(t('db_sync_error_fetch'));
            setStatus('idle');
        }
    };

    const handleImport = async () => {
        setStatus('importing');
        try {
            // Použitie writeBatch podľa pravidla Quota Guard
            const localPartsRef = doc(db, 'settings', 'parts');
            const currentLocal = await getDoc(localPartsRef);
            const currentData = currentLocal.exists() ? currentLocal.data().data || [] : [];

            // Merge unikátnych dielov
            const existingKeys = new Set(currentData.map((x: any) => x.p));
            const filteredNew = newParts.filter(p => !existingKeys.has(p.p));

            const batch = writeBatch(db);
            batch.update(localPartsRef, {
                data: [...currentData, ...filteredNew]
            });

            await batch.commit();
            onSyncSuccess(filteredNew.length);
            onClose();
        } catch (e) {
            alert("Import failed");
            setStatus('preview');
        }
    };

    return (
        <div className="fixed inset-0 z-[10000] flex items-center justify-center bg-black/90 backdrop-blur-md p-4 animate-fade-in">
            <div className="bg-slate-900 border-2 border-[#97bc1e]/50 rounded-3xl shadow-[0_0_50px_rgba(151,188,30,0.2)] w-full max-w-md p-8 relative overflow-hidden">
                {/* Background Decoration */}
                <div className="absolute top-0 right-0 w-32 h-32 bg-[#97bc1e]/5 rounded-full -mr-16 -mt-16 blur-2xl"></div>

                <div className="text-center mb-8 relative z-10">
                    <div className="w-16 h-16 bg-[#97bc1e]/10 rounded-2xl flex items-center justify-center mx-auto mb-4 border border-[#97bc1e]/30">
                        <svg className="w-8 h-8 text-[#97bc1e]" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 7v10c0 1.105 3.582 2 8 2s8-.895 8-2V7M4 7c0 1.105 3.582 2 8 2s8-.895 8-2M4 7c0-1.105 3.582-2 8-2s8 .895 8 2m-8 4v10" />
                        </svg>
                    </div>
                    <h3 className="text-2xl font-black text-white uppercase tracking-tighter">{t('db_sync_title')}</h3>
                </div>

                <div className="space-y-6 relative z-10">
                    {status === 'idle' && (
                        <>
                            <div>
                                <label className="block text-[10px] font-black text-slate-500 uppercase tracking-widest mb-2">{t('db_sync_pass_label')}</label>
                                <input 
                                    type="password" 
                                    value={password} 
                                    onChange={(e) => setPassword(e.target.value)}
                                    placeholder="••••••••"
                                    className="w-full h-14 bg-slate-800 border-2 border-slate-700 rounded-xl px-4 text-white text-center font-mono text-xl tracking-widest focus:border-[#97bc1e] transition-all outline-none"
                                    autoFocus
                                />
                            </div>
                            <button 
                                onClick={handleConnect}
                                className="w-full py-4 bg-[#97bc1e] hover:bg-[#86a81b] text-white rounded-xl font-black uppercase tracking-widest text-xs shadow-xl transition-all active:scale-95"
                            >
                                {t('db_sync_btn_connect')}
                            </button>
                        </>
                    )}

                    {status === 'connecting' && (
                        <div className="py-10 text-center space-y-4">
                            <div className="w-12 h-12 border-4 border-[#97bc1e] border-t-transparent rounded-full animate-spin mx-auto"></div>
                            <p className="text-slate-400 font-bold animate-pulse">{t('db_sync_connecting')}</p>
                        </div>
                    )}

                    {status === 'preview' && (
                        <div className="text-center space-y-6">
                            <p className="text-white text-lg font-bold">{t('db_sync_preview', { count: newParts.length })}</p>
                            <button 
                                onClick={handleImport}
                                className="w-full py-4 bg-teal-600 hover:bg-teal-500 text-white rounded-xl font-black uppercase tracking-widest text-xs shadow-xl"
                            >
                                {t('db_sync_import_btn')}
                            </button>
                        </div>
                    )}

                    {status === 'importing' && (
                        <div className="py-10 text-center space-y-4">
                            <div className="w-12 h-12 border-4 border-teal-500 border-t-transparent rounded-full animate-spin mx-auto"></div>
                            <p className="text-slate-400 font-bold">Synchronizujem lokálnu databázu...</p>
                        </div>
                    )}

                    <button 
                        onClick={onClose}
                        className="w-full py-3 text-slate-500 hover:text-slate-300 font-bold uppercase text-[10px] tracking-widest transition-colors"
                    >
                        {t('btn_cancel')}
                    </button>
                </div>
            </div>
        </div>
    );
};

export default MasterDbSyncModal;

import React, { useState, useMemo, memo } from 'react';
import { DBItem } from '../../App';
import { useLanguage } from '../LanguageContext';
import MasterDbSyncModal from '../modals/MasterDbSyncModal';

interface PartsSectionProps {
  parts: DBItem[];
  onAddPart: (val: string, desc?: string) => void;
  onBatchAddParts: (vals: string[]) => void;
  onDeletePart: (val: string) => void;
  onDeleteAllParts: () => void;
}

const PartsSection: React.FC<PartsSectionProps> = memo(({ parts, onAddPart, onBatchAddParts, onDeletePart, onDeleteAllParts }) => {
  const { t } = useLanguage();
  const [newPart, setNewPart] = useState('');
  const [newPartDesc, setNewPartDesc] = useState('');
  const [bulkParts, setBulkParts] = useState('');
  const [partSearch, setPartSearch] = useState('');
  const [isSyncModalOpen, setIsSyncModalOpen] = useState(false);

  const filteredParts = useMemo(() => {
      const q = partSearch.toLowerCase();
      if (!q) return parts;
      return parts.filter(p => 
        p.value.toLowerCase().includes(q) || 
        (p.description && p.description.toLowerCase().includes(q))
      );
  }, [parts, partSearch]);

  const cardClass = "bg-gray-800/40 border border-slate-700/50 rounded-2xl p-6 shadow-2xl backdrop-blur-sm";
  const inputClass = "w-full h-12 bg-slate-800/80 border border-slate-700 rounded-xl px-4 text-white text-base focus:outline-none focus:ring-2 focus:ring-teal-500/50 transition-all font-mono placeholder-gray-500 uppercase";
  const labelClass = "block text-xs font-black text-slate-500 uppercase tracking-[0.2em] mb-3";

  return (
    <div className={cardClass}>
      <div className="space-y-8">
        <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
          <h3 className="text-2xl font-black text-white uppercase tracking-tighter">DATABÁZA DIELOV (KYBLÍK)</h3>
          <div className="flex gap-3 w-full sm:w-auto">
            <button 
              onClick={() => setIsSyncModalOpen(true)}
              className="flex-1 sm:flex-none text-[10px] font-black text-[#97bc1e] bg-[#97bc1e]/10 px-4 py-3 rounded-xl border-2 border-[#97bc1e]/20 uppercase tracking-widest transition-all hover:bg-[#97bc1e]/20 flex items-center gap-2"
            >
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
              </svg>
              MASTER SYNC
            </button>
            <button onClick={() => { if(window.confirm('VYMAZAŤ VŠETKO?')) onDeleteAllParts(); }} className="flex-1 sm:flex-none text-[10px] font-black text-red-500 bg-red-500/10 px-4 py-3 rounded-xl border-2 border-red-500/20 uppercase tracking-widest transition-all hover:bg-red-500/20">{t('delete_all')}</button>
          </div>
        </div>

        <input value={partSearch} onChange={e=>setPartSearch(e.target.value)} placeholder="Hľadať v databáze..." className={inputClass} />

        <div className="grid grid-cols-2 md:grid-cols-4 gap-3 max-h-[350px] overflow-y-auto custom-scrollbar">
          {filteredParts.map(p => (
            <div key={p.id} className="bg-slate-950/40 h-12 px-4 rounded-xl border border-white/5 flex justify-between items-center text-xs font-mono group transition-colors hover:bg-slate-900">
              <span className="text-slate-300 truncate mr-2" title={p.description}>{p.value}</span>
              <button onClick={() => onDeletePart(p.value)} className="opacity-0 group-hover:opacity-100 text-red-500 font-black px-2 text-lg">×</button>
            </div>
          ))}
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-8 pt-8 border-t border-slate-800">
          <div className="space-y-4">
            <h4 className={labelClass}>SINGULAR ADDITION</h4>
            <input value={newPart} onChange={e=>setNewPart(e.target.value)} placeholder="Part No." className={inputClass} />
            <input value={newPartDesc} onChange={e=>setNewPartDesc(e.target.value)} placeholder="Description" className={inputClass} />
            <button onClick={() => { if(newPart) { onAddPart(newPart, newPartDesc); setNewPart(''); setNewPartDesc(''); } }} className="h-12 bg-teal-600 hover:bg-teal-500 text-white font-black px-6 rounded-xl uppercase tracking-widest text-xs transition-all w-full border-2 border-teal-500 shadow-lg">ADD SINGLE</button>
          </div>
          <div className="space-y-4">
            <h4 className={labelClass}>BULK IMPORT</h4>
            <textarea value={bulkParts} onChange={e=>setBulkParts(e.target.value)} placeholder="Part1;Desc1&#10;Part2;Desc2" className="w-full bg-slate-800/80 border border-slate-700 rounded-xl px-4 py-3 text-white text-base focus:outline-none focus:ring-2 focus:ring-teal-500/50 transition-all font-mono placeholder-gray-500 h-[120px] resize-none" />
            <button onClick={() => { if(bulkParts) { onBatchAddParts(bulkParts.split('\n')); setBulkParts(''); } }} className="h-12 bg-blue-600 hover:bg-blue-500 text-white font-black px-6 rounded-xl uppercase tracking-widest text-xs transition-all w-full border-2 border-blue-500 shadow-lg">IMPORT BATCH</button>
          </div>
        </div>
      </div>

      <MasterDbSyncModal 
        isOpen={isSyncModalOpen} 
        onClose={() => setIsSyncModalOpen(false)}
        onSyncSuccess={(count) => {
            alert(`Synchronizácia úspešná. Pridaných ${count} unikátnych dielov.`);
        }}
      />
    </div>
  );
});

export default PartsSection;

