import React, { createContext, useContext, ReactNode } from 'react';
import { useFirestoreData } from '../hooks/useFirestoreData';

// Týmto získame kompletný typ toho, čo vracia tvoj hook (dáta + funkcie)
// Nemusíme ručne vypisovať 50 funkcií, bude to vždy synchronizované
type UseFirestoreDataReturn = ReturnType<typeof useFirestoreData>;

const DataContext = createContext<UseFirestoreDataReturn | undefined>(undefined);

interface DataProviderProps {
  children: ReactNode;
  isAuthenticated: boolean;
  currentUserRole: string;
}

export const DataProvider: React.FC<DataProviderProps> = ({ 
  children, 
  isAuthenticated, 
  currentUserRole 
}) => {
  const data = useFirestoreData(isAuthenticated, currentUserRole);

  return (
    <DataContext.Provider value={data}>
      {children}
    </DataContext.Provider>
  );
};

export const useData = () => {
  const context = useContext(DataContext);
  if (context === undefined) {
    throw new Error('useData must be used within a DataProvider');
  }
  return context;
};

**Establishing Data Context**

I'm currently focused on constructing a React Context file, `src/context/DataContext.tsx`. My primary aim is to elegantly encapsulate the `useFirestoreData` hook. The ultimate goal here is to establish a streamlined, prop-drilling-free way to distribute and manage the application's data and associated functions across various components.


**Creating Data Context Structure**

\n\nI've generated the `context/DataContext.tsx` file, carefully mirroring the provided structure. This includes the `children`, `isAuthenticated`, and `currentUserRole` props for the provider and the `useData` custom hook. The context value is typed using `ReturnType<typeof useFirestoreData>`, ensuring type safety. I'm focusing on ensuring this setup seamlessly integrates with the existing hooks and components without any conflicts.
