                        <button 
                            onClick={handleStartInventory}
                            className="bg-[#4169E1] hover:bg-[#3151b1] text-white font-black py-8 px-16 rounded-2xl shadow-[0_0_25px_rgba(65,105,225,0.4)] transition-all active:scale-95 uppercase tracking-[0.25em] text-2xl border-2 border-[#5a81f3]"
                        >
                            📋 {language === 'sk' ? 'Spustiť Inventúru' : 'Start Inventory'}
                        </button>
                    </div>
                ) : (
                    <>
                        <div className="flex justify-between items-start sm:items-center mb-10 border-b border-gray-700 pb-6">
                            <div>
                                <h1 className="text-4xl font-extrabold text-[#4169E1] uppercase tracking-widest leading-none">
                                    {t('tab_inventory')}
                                </h1>
                                <div className="flex gap-6 items-center mt-3">
                                    <span className="bg-[#4169E1]/20 text-[#4169E1] text-xs font-black px-3 py-1 rounded-md border border-[#4169E1]/40 animate-pulse uppercase">Aktívna relácia</span>
                                    <p className="text-xs text-gray-500 uppercase font-mono">
                                        Položiek: <span className="text-white font-bold">{(scannedItems || []).length}</span>
                                    </p>
                                </div>
                            </div>

                            <button 
                                onClick={handleCancelInventory}
                                className={dangerButtonClass.replace('px-6 py-5', 'px-5 py-3 text-xs')}
                            >
                                🛑 {language === 'sk' ? 'Zrušiť reláciu' : 'Cancel session'}
                            </button>
                        </div>

                        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">Skladová Lokácia</label>
                                <input 
                                    ref={locationRef}
                                    type="text"
                                    value={location}
                                    onChange={(e) => setLocation(e.target.value.toUpperCase())}
                                    onKeyDown={(e) => e.key === 'Enter' && partRef.current?.focus()}
                                    placeholder="NAPR. MA123"
                                    className={inputBaseClass}
                                />
                            </div>
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">Číslo dielu</label>
                                <PartNumberInput 
                                    inputRef={partRef}
                                    parts={parts}
                                    onPartSelect={(p) => setPartNumber(p || '')}
                                    onInputChange={(val) => setPartNumber(val.toUpperCase())}
                                    onKeyDown={(e) => e.key === 'Enter' && batchRef.current?.focus()}
                                    placeholder={t('part_placeholder')}
                                    value={partNumber}
                                    onRequestPart={onRequestPart}
                                />
                            </div>
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">Batch / Číslo várky</label>
                                <div className="flex gap-3">
                                    <input 
                                        ref={batchRef}
                                        type="text"
                                        readOnly={isBatchMissing}
                                        value={batch}
                                        onChange={(e) => !isBatchMissing && setBatch(e.target.value.toUpperCase())}
                                        onKeyDown={(e) => e.key === 'Enter' && quantityRef.current?.focus()}
                                        placeholder={isBatchMissing ? '' : "489523"}
                                        className={`${inputBaseClass.replace('w-full', 'w-1/2')} ${isBatchMissing ? 'text-red-500 border-red-900/50 bg-red-900/10' : ''}`}
                                    />
                                    <button 
                                        type="button"
                                        onClick={toggleBatchMissing}
                                        className={`w-1/2 h-12 rounded-lg border-2 font-black uppercase text-xs text-white transition-all flex items-center justify-center gap-2 ${isBatchMissing ? 'bg-red-600 border-red-500 shadow-lg' : 'bg-[#4169E1]/20 border-[#4169E1] hover:bg-[#4169E1]/40'}`}
                                    >
                                        🏷️ {language === 'sk' ? 'Chýba štítok' : 'Label missing'}
                                    </button>
                                </div>
                            </div>
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">Množstvo</label>
                                <input 
                                    ref={quantityRef}
                                    type="text"
                                    inputMode="decimal"
                                    value={quantity}
                                    onChange={(e) => setQuantity(e.target.value.replace(/[^0-9.,]/g, '').slice(0, 7))}
                                    maxLength={7}
                                    onKeyDown={(e) => e.key === 'Enter' && handleAddItem()}
                                    placeholder="0"
                                    className={`${inputBaseClass} font-black text-lg`}
                                />
                            </div>
                        </div>

                        <button 
                            onClick={handleAddItem}
                            className="w-full mt-10 bg-[#4169E1] hover:bg-[#3151b1] text-white font-black py-6 rounded-2xl shadow-xl transition-all active:scale-95 uppercase tracking-widest text-xl border-2 border-[#5a81f3]"
                        >
                            Pridať do zoznamu
                        </button>
                    </>
                )}
            </div>

            {activeInventoryTask && (
                <div className="bg-gray-800 rounded-xl shadow-lg border border-gray-700 overflow-hidden">
                    <div className="p-5 sm:p-8 border-b border-gray-700 bg-gray-900/50 flex flex-col sm:row justify-between items-center gap-8">
                        <div className="flex items-center gap-6">
                            <h3 className="text-gray-400 font-black uppercase text-base tracking-[0.2em] leading-none">
                                {language === 'sk' ? 'SÚPIS POLOŽIEK' : 'ITEM INVENTORY'}
                            </h3>
                            <span className="bg-[#4169E1]/20 text-white border-2 border-[#4169E1] text-2xl px-5 py-2 rounded-xl font-black font-mono leading-none shadow-lg">
                                {(scannedItems || []).length}
                            </span>
                        </div>
                        <div className="flex flex-wrap w-full sm:w-auto gap-4">
                            <button 
                                onClick={handleClearAll} 
                                className={dangerButtonClass}
                            >
                                {language === 'sk' ? 'Zmazať všetko' : 'Clear all'}
                            </button>
                            <button 
                                onClick={handleExportAndFinish}
                                className="flex-1 sm:flex-none bg-green-700 hover:bg-green-600 text-white px-10 py-5 rounded-xl text-lg font-black shadow-xl transition-all active:scale-95 flex items-center justify-center gap-3 border-2 border-green-500 uppercase tracking-widest"
                            >
                                <svg xmlns="http://www.w3.org/2000/svg" className="h-8 w-8" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                                </svg>
                                EXPORT & UKONČIŤ
                            </button>
                        </div>
                    </div>

                    <div className="overflow-x-auto custom-scrollbar">
                        <table className="w-full text-left text-base border-collapse">
                            <thead className="bg-gray-900/30 text-gray-500 text-xs font-black uppercase tracking-widest border-b border-gray-700">
                                <tr>
                                    <th className="py-5 px-6">Čas</th>
                                    <th className="py-5 px-6">Lokácia</th>
                                    <th className="py-5 px-6">Číslo dielu</th>
                                    <th className="py-5 px-6">Batch</th>
                                    <th className="py-5 px-6 text-right">Počet (ks)</th>
                                    <th className="py-5 px-6 text-center"></th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-700/50">
                                {scannedItems && scannedItems.length > 0 ? (
                                    scannedItems.map(item => (
                                        <tr key={item.id} className="text-gray-300 hover:bg-gray-700/30 transition-colors group">
                                            <td className="py-5 px-6 text-xs text-gray-500 font-mono whitespace-nowrap">{new Date(item.timestamp).toLocaleTimeString('sk-SK')}</td>
                                            <td className="py-5 px-6 font-mono font-bold text-[#4169E1] text-lg">{item.location}</td>
                                            <td className="py-5 px-6 font-mono text-white text-base">{item.partNumber}</td>
                                            <td className={`py-5 px-6 font-mono text-base ${item.batch === '[CHÝBA ŠTÍTOK]' ? 'text-red-500 font-bold' : 'text-gray-500'}`}>
                                                {item.batch || '-'}
                                            </td>
                                            <td className="py-5 px-6 font-black text-white text-right font-mono text-xl">{item.quantity}</td>
                                            <td className="py-5 px-6 text-center w-24">
                                                <button 
                                                    onClick={() => handleDeleteItem(item.id)} 
                                                    className="w-16 h-16 flex items-center justify-center rounded-lg bg-red-900/30 text-red-500 hover:bg-red-800 hover:text-white border border-red-800/50 transition-all active:scale-90"
                                                >
                                                    <TrashIcon className="w-8 h-8" />
                                                </button>
                                            </td>
                                        </tr>
                                    ))
                                ) : (
                                    <tr><td colSpan={6} className="py-16 text-center text-gray-600 italic font-bold text-lg">Zoznam je prázdny. Začnite pridávať položky.</td></tr>
                                )}
                            </tbody>
                        </table>
                    </div>
                </div>
            )}

            {confirmModal.isOpen && createPortal(
                <div className="fixed inset-0 z-[9999] flex items-center justify-center bg-black/80 backdrop-blur-sm p-4 animate-fade-in" onClick={() => setConfirmModal(prev => ({...prev, isOpen: false}))}>
                    <div className="bg-gray-800 border-2 border-slate-700 rounded-2xl shadow-2xl w-full max-w-md p-8 relative" onClick={e => e.stopPropagation()}>
                        <div className="text-center mb-8">
                            <h3 className={`text-2xl font-black mb-3 uppercase tracking-tighter ${confirmModal.type === 'danger' ? 'text-red-500' : 'text-amber-500'}`}>
                                {confirmModal.title}
                            </h3>
                            <div className="text-gray-300 text-base leading-relaxed">
                                {confirmModal.message}
                            </div>
                        </div>
                        <div className="flex gap-4">
                            <button onClick={() => setConfirmModal(prev => ({...prev, isOpen: false}))} className="flex-1 py-4 bg-gray-700 text-gray-300 rounded-xl hover:bg-gray-600 font-black transition-all uppercase text-xs">
                                {t('btn_cancel')}
                            </button>
                            <button onClick={confirmModal.onConfirm} className={`flex-1 py-4 text-white rounded-xl font-black transition-all shadow-xl uppercase text-xs border-2 ${confirmModal.type === 'danger' ? 'bg-red-600 hover:bg-red-700 border-red-500' : 'bg-amber-600 hover:bg-amber-700 border-amber-500'}`}>
                                POTVRDIŤ
                            </button>
                        </div>
                    </div>
                </div>,
                document.body
            )}
        </div>
    );
};

export default InventoryTab;

import React, { useState, useMemo, useEffect } from 'react';
// Fixed: Importing Task from types/appTypes instead of App
import { Task } from '../../types/appTypes';
import { useLanguage } from '../LanguageContext';

declare var XLSX: any;

interface MissingItemsTabProps {
    tasks: Task[];
    onDeleteMissingItem: (id: string) => void;
    hasPermission: (perm: string) => boolean;
    resolveName: (username?: string | null) => string;
}

const TrashIcon: React.FC<{ className?: string }> = ({ className }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>;
const ClockIcon: React.FC<{ className?: string }> = ({ className }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>;
const AlertTriangleIcon: React.FC<{ className?: string }> = ({ className }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>;
const ChevronDownIcon: React.FC<{ className?: string }> = ({ className }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M19 9l-7 7-7-7" /></svg>;
const CheckIcon: React.FC<{ className?: string }> = ({ className }) => <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}><path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" /></svg>;

const MissingItemsTab: React.FC<MissingItemsTabProps> = ({ tasks, onDeleteMissingItem, hasPermission, resolveName }) => {
    const { t, language } = useLanguage();
    const [filterQuery, setFilterQuery] = useState('');
    const [currentTime, setCurrentTime] = useState(Date.now());
    const [expandedId, setExpandedId] = useState<string | null>(null);
    const [showOkAudits, setShowOkAudits] = useState(false);

    useEffect(() => {
        const interval = setInterval(() => setCurrentTime(Date.now()), 60000);
        return () => clearInterval(interval);
    }, []);

    const missingTasks = useMemo(() => {
        return tasks.filter(task => {
            const isActiveMissing = task.isMissing === true;
            const isOkAudit = task.auditResult === 'OK';
            return isActiveMissing || (showOkAudits && isOkAudit);
        }).sort((a, b) => {
            const timeA = a.completedAt || a.createdAt || 0;
            const timeB = b.completedAt || b.createdAt || 0;
            return timeB - timeA; 
        });
    }, [tasks, showOkAudits]);

    const filteredItems = useMemo(() => {
        if (!filterQuery) return missingTasks;
        const q = filterQuery.toLowerCase();
        return missingTasks.filter(task => 
            (task.partNumber && task.partNumber.toLowerCase().includes(q)) ||
            (task.workplace && task.workplace.toLowerCase().includes(q)) ||
            (task.missingReportedBy && task.missingReportedBy.toLowerCase().includes(q)) ||
            (task.missingReason && task.missingReason.toLowerCase().includes(q))
        );
    }, [missingTasks, filterQuery]);

    const formatAgeing = (ts?: number, isAudited?: boolean) => {
        if (isAudited) return language === 'sk' ? 'Auditované' : 'Audited';
        if (!ts) return null;
        const diffMs = currentTime - ts;
        const diffMin = Math.floor(diffMs / 60000);
        if (diffMin < 1) return t('miss_reported_just_now');
        return t('miss_reported_ago', { min: diffMin });
    };

    const getAgeingColor = (ts?: number, isAudited?: boolean) => {
        if (isAudited) return 'text-slate-500 font-bold';
        if (!ts) return 'text-slate-500';
        const diffMin = Math.floor((currentTime - ts) / 60000);
        if (diffMin > 120) return 'text-red-500 font-black animate-pulse';
        if (diffMin > 30) return 'text-orange-400 font-bold';
        return 'text-slate-400';
    };

    const getRowClass = (item: Task) => {
        const isOk = item.auditResult === 'OK';
        const reportTime = item.completedAt || item.createdAt || 0;
        let base = "transition-all cursor-pointer border-l-[6px] ";

        if (isOk) return base + "border-l-green-500 bg-green-500/5 opacity-70 hover:opacity-100 hover:bg-green-500/10";
        if (item.auditResult === 'NOK') return base + "border-l-slate-700 opacity-80 bg-slate-900/20";

        const diffMin = Math.floor((currentTime - reportTime) / 60000);
        if (diffMin > 120) return base + "border-l-red-600 hover:bg-teal-500/[0.04]";
        if (diffMin > 30) return base + "border-l-orange-500 hover:bg-teal-500/[0.04]";
        return base + "border-l-teal-500 hover:bg-teal-500/[0.04]";
    };

    const formatDateShort = (ts?: number) => {
        if (!ts) return '-';
        const d = new Date(ts);
        return d.toLocaleDateString('sk-SK', { day: '2-digit', month: '2-digit' }) + ' ' + 
               d.toLocaleTimeString('sk-SK', { hour: '2-digit', minute: '2-digit' });
    };

    return (
        <div className="max-w-7xl mx-auto space-y-8 pb-20 animate-fade-in px-2 md:px-0 text-slate-200">
            <div className="bg-[#1a1f2e] rounded-2xl shadow-2xl border border-slate-800 overflow-hidden ring-1 ring-white/5">
                <div className="p-5 sm:p-8 bg-slate-900/40 border-b border-slate-800 flex flex-col md:flex-row justify-between items-center gap-6">
                    <div className="flex items-center gap-4 w-full md:w-auto">
                        <div className="relative w-full md:w-[350px]">
                            <input 
                                type="text" 
                                value={filterQuery}
                                onChange={(e) => setFilterQuery(e.target.value)}
                                placeholder={t('task_search_placeholder')}
                                className="w-full h-12 bg-slate-800 border border-slate-700 rounded-xl px-4 pl-12 text-base text-white focus:outline-none focus:ring-2 focus:ring-teal-500/40 transition-all font-medium uppercase placeholder-gray-500 shadow-inner"
                            />
                            <svg xmlns="http://www.w3.org/2000/svg" className="absolute left-4 top-3.5 h-5 w-5 text-slate-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2.5} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
                        </div>
                        <button 
                            onClick={() => setShowOkAudits(!showOkAudits)}
                            className={`h-12 px-6 rounded-xl text-xs font-black uppercase tracking-widest transition-all flex items-center gap-2 border-2 ${showOkAudits ? 'bg-green-600/20 border-green-500 text-green-400' : 'bg-slate-800 border-slate-700 text-slate-500 hover:text-slate-300'}`}
                        >
                            {showOkAudits && <CheckIcon className="w-4 h-4" />}
                            {language === 'sk' ? 'Zobraziť OK audity' : 'Show OK audits'}
                        </button>
                    </div>
                </div>

                <div className="overflow-x-auto custom-scrollbar max-h-[750px]"> 
                    <table className="w-full text-left border-collapse min-w-[1100px] table-fixed">
                        <thead className="sticky top-0 z-20 shadow-md">
                            <tr className="bg-slate-950 text-slate-500 text-[10px] font-black uppercase tracking-[0.2em]">
                                <th className="py-6 px-8 w-[280px]">DIEL & PRACOVISKO</th>
                                <th className="py-6 px-8 w-[350px]">HLÁSENIE (DÔVOD & AGEING)</th>
                                <th className="py-6 px-8 w-[180px] text-center">VÝSLEDOK AUDITU</th>
                                <th className="py-6 px-8 w-20"></th>
                                {hasPermission('perm_btn_delete') && <th className="py-6 px-8 w-20"></th>}
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-slate-800">
                            {filteredItems.length > 0 ? (
                                filteredItems.map(item => {
                                    const reportTime = item.completedAt || item.createdAt || 0;
                                    const isAudited = !!item.auditResult;
                                    const isOk = item.auditResult === 'OK';
                                    const isExpanded = expandedId === item.id;

                                    return (
                                        <React.Fragment key={item.id}>
                                            <tr onClick={() => setExpandedId(isExpanded ? null : item.id)} className={getRowClass(item)}>
                                                <td className="py-6 px-8">
                                                    <div className="flex flex-col gap-2">
                                                        <span className="text-base font-black font-mono text-white bg-slate-800 px-4 py-1.5 rounded-lg border border-slate-700 w-fit shadow-md uppercase tracking-wide">
                                                            {item.partNumber}
                                                        </span>
                                                        <span className="text-[10px] font-black text-teal-400 bg-teal-500/10 px-2 py-0.5 rounded border border-teal-500/20 uppercase tracking-[0.15em] w-fit">
                                                            {item.workplace}
                                                        </span>
                                                    </div>
                                                </td>

                                                <td className="py-6 px-8">
                                                    <div className="flex flex-col gap-1.5">
                                                        <span className={`text-base font-black tracking-tight leading-snug ${isOk ? 'text-slate-500' : 'text-amber-500'}`}>
                                                            {item.missingReason}
                                                        </span>
                                                        <div className="flex items-center gap-2.5">
                                                            {!isAudited && (
                                                                <div className={`w-2 h-2 rounded-full ${Math.floor((currentTime - reportTime)/60000) > 120 ? 'bg-red-500 shadow-[0_0_8px_rgba(239,68,68,0.8)] animate-pulse' : 'bg-teal-500'}`}></div>
                                                            )}
                                                            {isOk && <CheckIcon className="w-3 h-3 text-green-500" />}
                                                            <span className={`text-[11px] font-black uppercase tracking-widest ${getAgeingColor(reportTime, isAudited)}`}>
                                                                {formatAgeing(reportTime, isAudited)}
                                                            </span>
                                                        </div>
                                                    </div>
                                                </td>

                                                <td className="py-6 px-8 text-center">
                                                    {item.auditResult ? (
                                                        <span className={`px-4 py-1 rounded-lg text-[10px] font-black uppercase tracking-widest inline-block border-2 ${item.auditResult === 'OK' ? 'bg-green-500/10 text-green-500 border-green-500/20' : 'bg-red-600/10 text-red-500 border-red-600/20'}`}>
                                                            {item.auditResult}
                                                        </span>
                                                    ) : (
                                                        <span className="text-[10px] text-slate-600 font-bold uppercase tracking-widest opacity-40 italic">Čaká na audit</span>
                                                    )}
                                                </td>

                                                <td className="py-6 px-8 text-center">
                                                    <ChevronDownIcon className={`w-6 h-6 text-slate-600 transition-transform duration-300 ${isExpanded ? 'rotate-180 text-teal-500' : ''}`} />
                                                </td>

                                                {hasPermission('perm_btn_delete') && (
                                                    <td className="py-6 px-8 text-center" onClick={(e) => { e.stopPropagation(); if (window.confirm(t('miss_delete_confirm'))) onDeleteMissingItem(item.id); }}>
                                                        <button className="text-slate-700 hover:text-red-500 p-3 transition-all bg-slate-800/50 rounded-xl group-hover:opacity-100">
                                                            <TrashIcon className="h-6 w-6" />
                                                        </button>
                                                    </td>
                                                )}
                                            </tr>

                                            {isExpanded && (
                                                <tr className="bg-slate-950/40 border-l-[6px] border-slate-800 animate-fade-in shadow-inner">
                                                    <td colSpan={hasPermission('perm_btn_delete') ? 5 : 4} className="p-10">
                                                        <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
                                                            <div className="space-y-6">
                                                                <h4 className="text-xs font-black text-teal-500 uppercase tracking-[0.25em] border-b-2 border-teal-900/50 pb-3">História záznamu</h4>
                                                                <div className="grid grid-cols-2 gap-8">
                                                                    <div className="space-y-2">
                                                                        <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Vytvoril (Zadal):</p>
                                                                        <p className="text-base font-black text-slate-200 uppercase truncate">{resolveName(item.createdBy)}</p>
                                                                        <p className="text-xs text-slate-500 font-mono italic">{formatDateShort(item.createdAt)}</p>
                                                                    </div>
                                                                    <div className="space-y-2">
                                                                        <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Nahlásil (Missing):</p>
                                                                        <p className="text-base font-black text-slate-200 uppercase truncate">{resolveName(item.missingReportedBy)}</p>
                                                                        <p className="text-xs text-slate-500 font-mono italic">{formatDateShort(item.completedAt)}</p>
                                                                    </div>
                                                                </div>
                                                            </div>
                                                            <div className="space-y-6">
                                                                <h4 className="text-xs font-black text-amber-500 uppercase tracking-[0.25em] border-b-2 border-amber-900/50 pb-3">Detail auditu</h4>
                                                                {item.auditedBy ? (
                                                                    <div className="space-y-5">
                                                                        <div className="flex justify-between items-start">
                                                                            <div className="space-y-2">
                                                                                <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Audítor:</p>
                                                                                <p className="text-base font-black text-amber-400 uppercase truncate">{resolveName(item.auditedBy)}</p>
                                                                                <p className="text-xs text-slate-500 font-mono italic">{formatDateShort(item.auditedAt || 0)}</p>
                                                                            </div>
                                                                            <div className={`px-6 py-3 rounded-2xl border-2 font-black text-sm tracking-[0.2em] shadow-lg ${item.auditResult === 'OK' ? 'bg-green-500/10 text-green-500 border-green-500/20' : 'bg-red-600/10 text-red-500 border-red-600/20'}`}>
                                                                                AUDIT {item.auditResult}
                                                                            </div>
                                                                        </div>
                                                                        <div className="bg-slate-900/80 p-5 rounded-xl border border-slate-800 shadow-inner">
                                                                            <p className="text-sm text-slate-300 italic">{item.auditNote || 'Bez poznámky'}</p>
                                                                        </div>
                                                                    </div>
                                                                ) : (
                                                                    <div className="py-10 flex flex-col items-center justify-center border-2 border-dashed border-slate-800 rounded-2xl bg-slate-900/20">
                                                                        <ClockIcon className="w-10 h-10 text-slate-800 mb-3" />
                                                                        <p className="text-xs text-slate-700 font-black uppercase tracking-[0.15em]">Tento záznam ešte nebol auditovaný</p>
                                                                    </div>
                                                                )}
                                                            </div>
                                                        </div>
                                                    </td>
                                                </tr>
                                            )}
                                        </React.Fragment>
                                    );
                                })
                            ) : (
                                <tr><td colSpan={hasPermission('perm_btn_delete') ? 5 : 4} className="py-40 text-center text-slate-600 uppercase tracking-widest font-black">Žiadne položky na zobrazenie</td></tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};

export default MissingItemsTab;

import React, { useState, useMemo } from 'react';
// Fixed: Importing Task from types/appTypes instead of App
import { Task } from '../../types/appTypes';
import { useLanguage } from '../LanguageContext';

declare var XLSX: any;

interface LogisticsCenterTabProps {
    tasks: Task[];
    onDeleteTask: (id: string) => void;
    hasPermission: (perm: string) => boolean;
    resolveName: (username?: string | null) => string;
}

const TrashIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
    </svg>
);

const ArrowDownIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 14l-7 7m0 0l-7-7m7 7V3" />
    </svg>
);

const ArrowUpIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 10l7-7m0 0l7 7m-7-7v18" />
    </svg>
);

const ClockIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z" />
    </svg>
);

const LogisticsCenterTab: React.FC<LogisticsCenterTabProps> = ({ tasks, onDeleteTask, hasPermission, resolveName }) => {
    const { t, language } = useLanguage();
    const [filterQuery, setFilterQuery] = useState('');
    const [quickFilter, setQuickFilter] = useState<'ALL' | 'INBOUND' | 'OUTBOUND' | 'PENDING'>('ALL');

    const logisticsTasks = useMemo(() => {
        return tasks.filter(task => task.isLogistics).sort((a, b) => {
            const timeA = a.createdAt || 0;
            const timeB = b.createdAt || 0;
            return timeB - timeA; 
        });
    }, [tasks]);

    const stats = useMemo(() => {
        let inbound = 0;
        let outbound = 0;
        let pending = 0;

        logisticsTasks.forEach(task => {
            const qty = parseFloat(task.quantity || '0');
            const op = (task.workplace || '').toUpperCase();

            if (op.includes('VYKLÁDKA') || op.includes('UNLOADING') || op.includes('PRÍJEM')) {
                inbound += qty;
            } else if (op.includes('NAKLÁDKA') || op.includes('LOADING') || op.includes('EXPEDÍCIA')) {
                outbound += qty;
            }

            if (!task.isDone) {
                pending++;
            }
        });

        return { inbound, outbound, pending };
    }, [logisticsTasks]);

    const filteredItems = useMemo(() => {
        let items = logisticsTasks;

        if (quickFilter === 'INBOUND') {
            items = items.filter(t => (t.workplace || '').toUpperCase().includes('VYKLÁDKA') || (t.workplace || '').toUpperCase().includes('UNLOADING'));
        } else if (quickFilter === 'OUTBOUND') {
            items = items.filter(t => (t.workplace || '').toUpperCase().includes('NAKLÁDKA') || (t.workplace || '').toUpperCase().includes('LOADING'));
        } else if (quickFilter === 'PENDING') {
            items = items.filter(t => !t.isDone);
        }

        if (!filterQuery) return items;
        const q = filterQuery.toLowerCase();
        return items.filter(task => 
            (task.partNumber && task.partNumber.toLowerCase().includes(q)) || 
            (task.workplace && task.workplace.toLowerCase().includes(q)) || 
            (task.createdBy && task.createdBy.toLowerCase().includes(q)) ||
            (task.completedBy && task.completedBy.toLowerCase().includes(q)) ||
            (task.note && task.note.toLowerCase().includes(q))
        );
    }, [logisticsTasks, filterQuery, quickFilter]);

    const formatTime = (ts?: number) => {
        if (!ts) return '-';
        return new Date(ts).toLocaleString('sk-SK', { day: '2-digit', month: '2-digit', hour: '2-digit', minute: '2-digit' });
    };

    const getQuantityString = (task: Task) => {
        if (!task.quantity) return '-';
        let unitLabel = task.quantityUnit || '';
        if (unitLabel === 'pcs') unitLabel = t('unit_pcs_short');
        if (unitLabel === 'boxes') unitLabel = t('unit_boxes_short');
        if (unitLabel === 'pallet') unitLabel = t('unit_pallet_short');
        return `${task.quantity} ${unitLabel}`;
    };

    const renderFormattedText = (text: string | undefined) => {
        if (!text) return '-';
        if (!text.includes(';')) return text;
        const parts = text.split(';');
        return parts.map((part, index) => (
            <React.Fragment key={index}>
                {part.trim()}
                {index < parts.length - 1 && (
                    <span className="mx-1.5 text-teal-500/40 font-light inline-block scale-90">→</span>
                )}
            </React.Fragment>
        ));
    };

    const handleExport = () => {
        if (typeof XLSX === 'undefined') {
            alert('Export library missing.');
            return;
        }
        const data = filteredItems.map(item => ({
            [t('miss_th_created')]: formatTime(item.createdAt),
            [t('miss_th_creator')]: resolveName(item.createdBy),
            [t('log_th_reference')]: item.partNumber || '-',
            [language === 'sk' ? 'ŠPZ' : 'PLATE']: item.note || '-',
            [t('log_th_operation')]: item.workplace || '-',
            [t('log_th_quantity')]: getQuantityString(item),
            [t('log_th_priority')]: item.priority || 'NORMAL',
            [t('log_th_status')]: item.isDone ? t('status_completed') : t('status_open'),
            [t('log_th_completed_by')]: resolveName(item.completedBy),
            [t('miss_th_when')]: formatTime(item.completedAt)
        }));

        const ws = XLSX.utils.json_to_sheet(data);
        const wb = XLSX.utils.book_new();
        XLSX.utils.book_append_sheet(wb, ws, t('log_sheet_name'));
        XLSX.writeFile(wb, `Logisticke_Centrum_${new Date().toISOString().slice(0,10)}.xlsx`);
    };

    const handleDelete = (id: string) => {
        if (window.confirm(t('miss_delete_confirm'))) {
            onDeleteTask(id);
        }
    }

    return (
        <div className="max-w-7xl mx-auto space-y-6 pb-20 animate-fade-in">
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
                <div onClick={() => setQuickFilter('INBOUND')} className={`cursor-pointer bg-gray-800 p-5 rounded-2xl border transition-all hover:scale-[1.02] ${quickFilter === 'INBOUND' ? 'border-green-500 shadow-[0_0_15px_rgba(34,197,94,0.3)]' : 'border-gray-700 shadow-lg'}`}>
                    <div className="flex justify-between items-start">
                        <div>
                            <p className="text-gray-500 text-[10px] font-bold uppercase tracking-widest">{language === 'sk' ? 'PRÍJEM (Vykládka)' : 'INBOUND'}</p>
                            <p className="text-3xl font-black text-green-400 mt-1">{stats.inbound} <span className="text-xs font-normal text-gray-500">pal</span></p>
                        </div>
                        <div className="p-2 bg-green-500/10 rounded-lg text-green-500">
                            <ArrowDownIcon className="w-6 h-6" />
                        </div>
                    </div>
                </div>

                <div onClick={() => setQuickFilter('OUTBOUND')} className={`cursor-pointer bg-gray-800 p-5 rounded-2xl border transition-all hover:scale-[1.02] ${quickFilter === 'OUTBOUND' ? 'border-sky-500 shadow-[0_0_15px_rgba(14,165,233,0.3)]' : 'border-gray-700 shadow-lg'}`}>
                    <div className="flex justify-between items-start">
                        <div>
                            <p className="text-gray-500 text-[10px] font-bold uppercase tracking-widest">{language === 'sk' ? 'EXPEDÍCIA (Nakládka)' : 'OUTBOUND'}</p>
                            <p className="text-3xl font-black text-sky-400 mt-1">{stats.outbound} <span className="text-xs font-normal text-gray-500">pal</span></p>
                        </div>
                        <div className="p-2 bg-sky-500/10 rounded-lg text-sky-500">
                            <ArrowUpIcon className="w-6 h-6" />
                        </div>
                    </div>
                </div>

                <div onClick={() => setQuickFilter('PENDING')} className={`cursor-pointer bg-gray-800 p-5 rounded-2xl border transition-all hover:scale-[1.02] ${quickFilter === 'PENDING' ? 'border-orange-500 shadow-[0_0_15px_rgba(249,115,22,0.3)]' : 'border-gray-700 shadow-lg'}`}>
                    <div className="flex justify-between items-start">
                        <div>
                            <p className="text-gray-500 text-[10px] font-bold uppercase tracking-widest">{language === 'sk' ? 'V ČAKANÍ' : 'PENDING'}</p>
                            <p className="text-3xl font-black text-orange-400 mt-1">{stats.pending} <span className="text-xs font-normal text-gray-500">úloh</span></p>
                        </div>
                        <div className="p-2 bg-orange-500/10 rounded-lg text-orange-500">
                            <ClockIcon className="w-6 h-6" />
                        </div>
                    </div>
                </div>
            </div>

            <div className="bg-gray-800 rounded-2xl shadow-2xl border border-gray-700 overflow-hidden">
                <div className="p-4 sm:p-6 bg-gray-900/40 border-b border-gray-700 flex flex-col md:flex-row justify-between items-center gap-4">
                    <div className="flex items-center gap-4 w-full md:w-auto">
                        <div className="relative flex-grow md:flex-grow-0 md:w-80">
                            <input 
                                type="text" 
                                value={filterQuery}
                                onChange={(e) => setFilterQuery(e.target.value)}
                                placeholder={t('task_search_placeholder')}
                                className="w-full h-10 bg-gray-800 border border-gray-600 rounded-xl px-4 pl-10 text-sm text-white focus:outline-none focus:ring-2 focus:ring-sky-500 transition-all font-medium uppercase placeholder-gray-500"
                            />
                            <svg xmlns="http://www.w3.org/2000/svg" className="absolute left-3 top-3 h-4 w-4 text-gray-500" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                            </svg>
                        </div>
                        <div className="hidden sm:flex bg-gray-800 h-10 p-1 rounded-lg border border-gray-700">
                            <button onClick={() => setQuickFilter('ALL')} className={`px-3 rounded-md text-xs font-bold transition-all ${quickFilter === 'ALL' ? 'bg-gray-700 text-white shadow-sm' : 'text-gray-500 hover:text-gray-300'}`}>{t('filter_all')}</button>
                            <button onClick={() => setQuickFilter('PENDING')} className={`px-3 rounded-md text-xs font-bold transition-all ${quickFilter === 'PENDING' ? 'bg-orange-600/20 text-orange-400' : 'text-gray-500 hover:text-gray-300'}`}>{language === 'sk' ? 'Otvorené' : 'Open'}</button>
                        </div>
                    </div>

                    <button 
                        onClick={handleExport}
                        className="w-full md:w-auto bg-green-700 hover:bg-green-600 text-white px-6 py-2.5 rounded-xl text-sm font-bold shadow-lg transition-all active:scale-95 flex items-center justify-center gap-2"
                    >
                        <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                        </svg>
                        {t('export_excel')}
                    </button>
                </div>

                <div className="overflow-x-auto custom-scrollbar"> 
                    <table className="w-full text-left border-collapse min-w-[900px]">
                        <thead>
                            <tr className="bg-gray-900/50 text-gray-400 text-[10px] font-bold uppercase tracking-widest border-b border-gray-700">
                                <th className="py-4 px-6">{t('miss_th_created')}</th>
                                <th className="py-4 px-6">{t('log_th_reference')}</th>
                                <th className="py-4 px-6">{t('log_th_operation')}</th>
                                <th className="py-4 px-6 text-center">{t('log_th_quantity')}</th>
                                <th className="py-4 px-6 text-center">{t('log_th_priority')}</th>
                                <th className="py-4 px-6">{t('log_th_status')}</th>
                                <th className="py-4 px-6">{t('log_th_completed_by')}</th>
                                <th className="py-4 px-6 text-right">{t('miss_th_when')}</th>
                                {hasPermission('perm_btn_delete') && <th className="py-4 px-6"></th>}
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-700/50">
                            {filteredItems.length > 0 ? (
                                filteredItems.map(item => {
                                    const op = (item.workplace || '').toUpperCase();
                                    const isInbound = op.includes('VYKLÁDKA') || op.includes('UNLOADING');
                                    const isOutbound = op.includes('NAKLÁDKA') || op.includes('LOADING');

                                    return (
                                        <tr key={item.id} className={`transition-all ${item.isDone ? 'opacity-60 bg-gray-900/10' : 'hover:bg-gray-700/30'}`}>
                                            <td className="py-4 px-6 whitespace-nowrap">
                                                <p className="text-xs text-white font-mono">{formatTime(item.createdAt).split(',')[1]}</p>
                                                <p className="text-[10px] text-gray-500">{formatTime(item.createdAt).split(',')[0]}</p>
                                            </td>
                                            <td className="py-4 px-6">
                                                <div className="flex flex-col gap-1">
                                                    <span className="text-sm font-black font-mono text-white bg-gray-900/50 px-3 py-1.5 rounded-lg border border-gray-700 w-fit">
                                                        {renderFormattedText(item.partNumber)}
                                                    </span>
                                                    {item.note && (
                                                        <span className="text-[10px] text-gray-500 font-bold uppercase tracking-widest pl-1">
                                                            ŠPZ: <span className="text-sky-500/70">{item.note}</span>
                                                        </span>
                                                    )}
                                                </div>
                                            </td>
                                            <td className="py-4 px-6">
                                                <div className="flex items-center gap-3">
                                                    <div className={`p-1.5 rounded-md ${isInbound ? 'bg-green-500/10 text-green-500' : isOutbound ? 'bg-sky-500/10 text-sky-500' : 'bg-gray-700 text-gray-400'}`}>
                                                        {isInbound ? <ArrowDownIcon className="w-4 h-4" /> : isOutbound ? <ArrowUpIcon className="w-4 h-4" /> : <TruckIcon className="w-4 h-4" />}
                                                    </div>
                                                    <span className={`text-xs font-bold uppercase tracking-wide ${isInbound ? 'text-green-400' : isOutbound ? 'text-sky-400' : 'text-gray-300'}`}>
                                                        {item.workplace}
                                                    </span>
                                                </div>
                                            </td>
                                            <td className="py-4 px-6 text-center">
                                                <span className="text-sm font-bold text-white">{getQuantityString(item)}</span>
                                            </td>
                                            <td className="py-4 px-6 text-center">
                                                <span className={`text-[10px] font-black uppercase px-2 py-1 rounded-full border ${item.priority === 'URGENT' ? 'bg-red-500/10 text-red-500 border-red-500/20' : 'bg-gray-700/30 text-gray-400 border-gray-600/30'}`}>
                                                    {t(item.priority === 'URGENT' ? 'prio_urgent' : item.priority === 'LOW' ? 'prio_low' : 'prio_normal')}
                                                </span>
                                            </td>
                                            <td className="py-4 px-6">
                                                {item.isDone ? (
                                                    <span className="inline-flex items-center gap-1.5 text-green-400 text-xs font-bold">
                                                        <div className="w-1.5 h-1.5 rounded-full bg-green-500 shadow-[0_0_5px_rgba(34,197,94,0.5)]"></div>
                                                        {t('status_completed')}
                                                    </span>
                                                ) : (
                                                    <span className="inline-flex items-center gap-1.5 text-orange-400 text-xs font-bold animate-pulse">
                                                        <div className="w-1.5 h-1.5 rounded-full bg-orange-500"></div>
                                                        {t('status_open')}
                                                    </span>
                                                )}
                                            </td>
                                            <td className="py-4 px-6 whitespace-nowrap">
                                                <div className="flex items-center gap-2">
                                                    <div className="w-6 h-6 rounded-full bg-gray-700 flex items-center justify-center text-[10px] font-bold text-gray-400">
                                                        {(resolveName(item.completedBy) || '?').charAt(0).toUpperCase()}
                                                    </div>
                                                    <span className="text-xs text-gray-300 font-medium truncate max-w-[100px]">{resolveName(item.completedBy)}</span>
                                                </div>
                                            </td>
                                            <td className="py-4 px-6 text-right whitespace-nowrap">
                                                <p className="text-[10px] text-gray-500 font-mono">{formatTime(item.completedAt)}</p>
                                            </td>
                                            {hasPermission('perm_btn_delete') && (
                                                <td className="py-4 px-6 text-center">
                                                    <button onClick={() => handleDelete(item.id)} className="text-gray-600 hover:text-red-500 p-2 transition-colors">
                                                        <TrashIcon className="h-5 w-5" />
                                                    </button>
                                                </td>
                                            )}
                                        </tr>
                                    );
                                })
                            ) : (
                                <tr>
                                    <td colSpan={hasPermission('perm_btn_delete') ? 10 : 9} className="py-20 text-center text-gray-600 italic">
                                        <div className="flex flex-col items-center gap-3">
                                            <svg xmlns="http://www.w3.org/2000/svg" className="h-12 w-12 text-gray-800" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                                                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1} d="M9 17v-2m3 2v-4m3 4v-6m2 10H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                                            </svg>
                                            {t('no_data')}
                                        </div>
                                    </td>
                                </tr>
                            )}
                        </tbody>
                    </table>
                </div>
            </div>
        </div>
    );
};

const TruckIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16V6a1 1 0 00-1-1H4a1 1 0 00-1 1v10a1 1 0 001 1h1m8-1a1 1 0 01-1 1H9m4-1V8a1 1 0 011-1h2.586a1 1 0 01.707.293l3.414 3.414a1 1 0 01.293.707V16a1 1 0 01-1 1h-1m-6-1a1 1 0 001 1h1M5 17a2 2 0 104 0m-4 0a2 2 0 114 0m6 0a2 2 0 104 0m-4 a2 2 0 114 0" />
    </svg>
);

