                            >
                              ×
                            </button>
                          </>
                        )}
                      </div>
                  </div>
                </div>
              );
            })}
            {mapSectors.length === 0 && (
                <p className="text-center py-6 text-slate-600 italic text-xs uppercase tracking-widest font-bold">Žiadne sektory nie sú definované</p>
