import React from 'react';
import PartSearchScreen from './components/PartSearchScreen';
import { useData } from './context/DataContext';
import { SystemConfig } from './types/appTypes';

interface AppAuthenticatedProps {
  currentUser: string;
  currentUserRole: 'ADMIN' | 'USER' | 'LEADER';
  onLogout: () => void;
  systemConfig: SystemConfig;
  onUpdateSystemConfig: (config: Partial<SystemConfig>) => void;
  onUpdateAdminKey: (oldK: string, newK: string) => Promise<void>;
  onToggleAdminLock: (val: boolean) => void;
  installPrompt: any;
  onInstallApp: () => void;
}

const AppAuthenticated: React.FC<AppAuthenticatedProps> = (props) => {
  // 1. Vytiahneme VŠETKY dáta a funkcie z nového Contextu
  const data = useData();

  // 2. Vložíme ich do PartSearchScreen spolu s props, ktoré prichádzajú zhora (auth/security)
  return (
    <PartSearchScreen
      // Dáta z Contextu (tasks, users, onAddTask, atď.)
      {...data}

      // Dáta z App.tsx (Auth, Security, PWA)
      currentUser={props.currentUser}
      currentUserRole={props.currentUserRole}
      onLogout={props.onLogout}

      // Security props (ktoré sú v App.tsx cez useAppSecurity)
      // Poznámka: PartSearchScreen očakáva tieto props, lebo SettingsTab ich potrebuje
      // V budúcnosti refaktorujeme aj toto, ale teraz to len posúvame ďalej (Prop Drilling Bridge)
      /* POZNÁMKA: PartSearchScreen momentálne očakáva 'systemConfig' a handlery.
         Tieto neprichádzajú z useData, ale z useAppSecurity v App.tsx.
      */
      // Tieto props sú už zahrnuté v type PartSearchScreenProps, 
      // musíme zabezpečiť, aby sedeli názvy.
      // Keďže data obsahuje 'systemConfig' z useFirestoreData? 
      // POZOR: useFirestoreData nevracia systemConfig, ten je v useAppSecurity.
      // Takže ho musíme poslať explicitne z props.

      systemConfig={props.systemConfig} // Prepíše prípadné undefined z data
      onUpdateSystemConfig={props.onUpdateSystemConfig}
      onUpdateAdminKey={props.onUpdateAdminKey}
      onToggleAdminLock={props.onToggleAdminLock}

      // PWA
      installPrompt={props.installPrompt}
      onInstallApp={props.onInstallApp}
    />
  );
};

export default AppAuthenticated;

