import { useState, useEffect, useRef, useCallback } from 'react';
import { db } from '../firebase';
import { 
  collection, 
  onSnapshot, 
  query, 
  orderBy,
  where,
  limit,
  doc,
  addDoc,
  updateDoc,
  deleteDoc,
  getDocs,
  writeBatch,
  getDoc,
  setDoc,
  arrayUnion,
  getCountFromServer
} from 'firebase/firestore';
import { Task, UserData, DBItem, MapSector, PartRequest, BOMRequest, BreakSchedule, SystemBreak, Role, Permission, Notification, PriorityLevel } from '../types/appTypes';
import { PRIORITY_ORDER } from '../constants/uiConstants';

export const useFirestoreData = (isAuthenticated: boolean, currentUser: string, currentUserRole: string) => {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [users, setUsers] = useState<UserData[]>([]);
  const [partsMap, setPartsMap] = useState<Record<string, string>>({});
  const [bomMap, setBomMap] = useState<Record<string, any>>({});
  const [workplaces, setWorkplaces] = useState<DBItem[]>([]);
  const [missingReasons, setMissingReasons] = useState<DBItem[]>([]);
  const [logisticsOperations, setLogisticsOperations] = useState<DBItem[]>([]); 
  const [mapSectors, setMapSectors] = useState<MapSector[]>([]);
  const [partRequests, setPartRequests] = useState<PartRequest[]>([]);
  const [bomRequests, setBomRequests] = useState<BOMRequest[]>([]);
  const [breakSchedules, setBreakSchedules] = useState<BreakSchedule[]>([]);
  const [systemBreaks, setSystemBreaks] = useState<SystemBreak[]>([]);
  const [isBreakActive, setIsBreakActive] = useState(false);
  const [roles, setRoles] = useState<Role[]>([]);
  const [permissions, setPermissions] = useState<Permission[]>([]);
  const [notifications, setNotifications] = useState<Notification[]>([]);

  const isFirstLoad = useRef(true);
  const rolesRef = useRef<Role[]>([]);
  const permissionsRef = useRef<Permission[]>([]);
  const currentUserRoleRef = useRef(currentUserRole);

  useEffect(() => { rolesRef.current = roles; }, [roles]);
  useEffect(() => { permissionsRef.current = permissions; }, [permissions]);
  useEffect(() => { currentUserRoleRef.current = currentUserRole; }, [currentUserRole]);

  // --- CRUD OPERÁCIE PRE ÚLOHY ---

  const onAddTask = async (pn: string, wp: string | null, qty: string | null, unit: string | null, prio: PriorityLevel, isLogistics: boolean = false, note?: string) => {
    let finalUnit = unit;
    const description = partsMap[pn];
    if (description) {
        if (description.includes('S0001S')) finalUnit = 'pcs';
        else if (description.includes('S0002S')) finalUnit = 'boxes';
        else if (description.includes('S0003S')) finalUnit = 'pallet';
    }
    const formattedDate = new Date().toLocaleString('sk-SK');
    let fQty = qty || ''; 
    if(finalUnit === 'boxes') fQty = `${qty} box`; 
    if(finalUnit === 'pallet') fQty = `${qty} pal`;
    let text = `${formattedDate} / ${pn} / ${wp} / Počet: ${fQty}`;
    if (note) text += ` / Pozn: ${note}`;
    const now = Date.now();
    await addDoc(collection(db, 'tasks'), { text, partNumber: pn, workplace: wp, quantity: qty, quantityUnit: finalUnit, standardTime: 0, isDone:false, priority:prio, createdAt:now, createdBy:currentUser, isLogistics, isProduction: !isLogistics, isInProgress: false, note: note || null, expireAt: now + (90 * 24 * 60 * 60 * 1000) });
  };

  const onUpdateTask = async (id: string, updates: Partial<Task>) => { await updateDoc(doc(db, 'tasks', id), updates); };

  const onToggleTask = async (id: string) => {
    const t = tasks.find(x => x.id === id);
    if(t) {
        const newState = !t.isDone;
        await updateDoc(doc(db,'tasks',id), { isDone:newState, status:newState?'completed':null, completionTime:newState?new Date().toLocaleTimeString('sk-SK'):null, completedBy:newState?currentUser:null, completedAt:newState?Date.now():null, isInProgress:false });
    }
  };

  const onMarkAsIncorrect = async (id: string) => { await updateDoc(doc(db,'tasks',id), {isDone:true, status:'incorrectly_entered'}); };
  const onEditTask = async (id: string, txt: string, prio?: PriorityLevel) => { await updateDoc(doc(db,'tasks',id), {text:txt, priority:prio}); };
  const onDeleteTask = async (id: string) => { await deleteDoc(doc(db,'tasks',id)); };

  const onToggleMissing = async (id: string, r?: string) => {
      const t = tasks.find(x => x.id === id);
      if (t) await updateDoc(doc(db,'tasks',id), { isMissing: !t.isMissing, missingReason: !t.isMissing ? (r || 'Iné') : null, missingReportedBy: !t.isMissing ? currentUser : null });
  };

  const onSetInProgress = async (id: string) => {
      const t = tasks.find(x => x.id === id);
      if (t) await updateDoc(doc(db,'tasks',id), { isInProgress: !t.isInProgress, inProgressBy: !t.isInProgress ? currentUser : null, startedAt: (!t.isInProgress && !t.startedAt) ? Date.now() : t.startedAt });
  };

  const onToggleBlock = async (id: string) => {
      const t = tasks.find(x => x.id === id);
      if (t) await updateDoc(doc(db,'tasks',id), { isBlocked: !t.isBlocked, blockedBy: !t.isBlocked ? currentUser : null });
  };

  const onToggleManualBlock = async (id: string) => {
      const t = tasks.find(x => x.id === id);
      if (t) await updateDoc(doc(db,'tasks',id), { isManualBlocked: !t.isManualBlocked });
  };

  const onExhaustSearch = async (id: string) => { await updateDoc(doc(db,'tasks',id), { searchExhausted: true, isBlocked: false }); };
  const onAddNote = async (id: string, n: string) => { await updateDoc(doc(db,'tasks',id), { note: n }); };
  const onReleaseTask = async (id: string) => { await updateDoc(doc(db,'tasks',id), { isInProgress: false, inProgressBy: null }); };
  const onStartAudit = async (id: string) => { await updateDoc(doc(db,'tasks',id), { isAuditInProgress: true, auditBy: currentUser }); };
  const onFinishAudit = async (id: string, res: 'found' | 'missing', note: string) => { await updateDoc(doc(db,'tasks',id), { auditResult: res === 'found' ? 'OK' : 'NOK', auditNote: note, isAuditInProgress: false, auditedBy: currentUser, auditedAt: Date.now() }); };
  const onDeleteMissingItem = async (id: string) => { await deleteDoc(doc(db,'tasks',id)); };

  const onArchiveTasks = async () => {
      const q = query(collection(db, 'tasks'), where('isDone', '==', true));
      const s = await getDocs(q);
      if (s.empty) return { success: true, count: 0 };
      const batch = writeBatch(db);
      s.docs.forEach(d => batch.delete(d.ref));
      await batch.commit();
      return { success: true, count: s.size };
  };

  const onDailyClosing = async () => {
    const q = query(collection(db, 'tasks'), where('isDone', '==', true));
    const s = await getDocs(q);
    const draftRef = doc(db, 'settings', 'draft');
    const existing = await getDoc(draftRef);
    const existingData = existing.exists() ? existing.data().data || [] : [];
    const newTasks = s.docs.map(d => ({ ...d.data(), id: d.id }));
    await setDoc(draftRef, { data: [...existingData, ...newTasks] });
    const batch = writeBatch(db);
    s.docs.forEach(d => batch.delete(d.ref));
    await batch.commit();
    return { success: true, count: s.size };
  };

  const onGetDocCount = async () => {
    const snap = await getCountFromServer(collection(db, 'tasks'));
    return snap.data().count;
  };

  const onPurgeOldTasks = async () => {
    const threshold = Date.now() - (90 * 24 * 60 * 60 * 1000);
    const q = query(collection(db, 'tasks'), where('createdAt', '<', threshold), limit(500));
    const s = await getDocs(q);
    const batch = writeBatch(db);
    s.docs.forEach(d => batch.delete(d.ref));
    await batch.commit();
    return s.size;
  };

  const onFetchArchivedTasks = async () => {
    const s = await getDoc(doc(db, 'settings', 'draft'));
    return s.exists() ? s.data().data || [] : [];
  };

  // --- CRUD OPERÁCIE PRE UŽÍVATEĽOV ---

  const onAddUser = async (u: UserData) => { await addDoc(collection(db, 'users'), { ...u, canExportAnalytics: false }); };
  const onUpdatePassword = async (u: string, p: string) => { const user = users.find(us => us.username === u); if(user) { await updateDoc(doc(db,'users', user.id!), {password: p}); } };
  const onUpdateNickname = async (u: string, n: string) => { const user = users.find(us => us.username === u); if(user) { await updateDoc(doc(db,'users', user.id!), {nickname: n}); } };
  const onUpdateUserRole = async (u: string, r: any) => { const user = users.find(us => us.username === u); if(user) { await updateDoc(doc(db,'users', user.id!), {role: r}); } };
  const onDeleteUser = async (u: string) => { const user = users.find(us => us.username === u); if(user) { await deleteDoc(doc(db,'users', user.id!)); } };
  const onUpdateExportPermission = async (username: string, canExport: boolean) => {
    const user = users.find(u => u.username === username);
    if (user && user.id) await updateDoc(doc(db, 'users', user.id), { canExportAnalytics: canExport });
  };
  const onVerifyAdminPassword = (p: string) => users.some(u => u.role === 'ADMIN' && u.password === p);

  // --- OSTATNÉ POMOCNÉ FUNKCIE ---

  const checkPermissionRef = useCallback((permName: string) => {
      const currentRole = currentUserRoleRef.current;
      if (currentRole === 'ADMIN') return true;
      const r = rolesRef.current.find(ro => ro.name === currentRole);
      if (!r) return false;
      return permissionsRef.current.some(p => p.roleId === r.id && p.permissionName === permName);
  }, []);

  const checkBreakStatus = useCallback(() => {
      const now = new Date();
      const currentHHMM = now.getHours().toString().padStart(2, '0') + ':' + 
                          now.getMinutes().toString().padStart(2, '0');
      const isScheduledActive = (breakSchedules || []).some(b => 
          currentHHMM >= b.startTime && currentHHMM <= b.endTime
      );
      const isManualActive = (systemBreaks || []).some(b => b.isActive);
      setIsBreakActive(isScheduledActive || isManualActive);
  }, [breakSchedules, systemBreaks]);

  useEffect(() => {
      checkBreakStatus(); 
      const interval = setInterval(checkBreakStatus, 30000); 
      return () => clearInterval(interval);
  }, [checkBreakStatus]);

  useEffect(() => {
    if (!isAuthenticated) return;
    const threshold = Date.now() - (3 * 24 * 60 * 60 * 1000);
    const q = query(collection(db, 'tasks'), where('createdAt', '>=', threshold), limit(300)); 

    return onSnapshot(q, (snapshot) => {
      const newTasks = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as Task));
      if (!isFirstLoad.current) {
          snapshot.docChanges().forEach((change) => {
              if (change.type === 'added') {
                  const task = change.doc.data() as Task;
                  if (task.createdAt && (Date.now() - task.createdAt < 10000)) {
                      if (checkPermissionRef('perm_play_sound')) {
                          try {
                              const audio = new Audio('https://codeskulptor-demos.commondatastorage.googleapis.com/pang/pop.mp3');
                              audio.play().catch(e => console.log('Sound blocked', e));
                          } catch (e) {}
                      }
                  }
              }
          });
      }
      isFirstLoad.current = false;
      const sortedTasks = newTasks.sort((a, b) => {
        if (a.isDone !== b.isDone) return a.isDone ? 1 : -1;
        if (a.isDone) {
            const timeA = a.completedAt || a.createdAt || 0;
            const timeB = b.completedAt || b.createdAt || 0;
            return timeB - timeA; 
        }
        const aManBlocked = a.isManualBlocked ? 1 : 0;
        const bManBlocked = b.isManualBlocked ? 1 : 0;
        if (aManBlocked !== bManBlocked) return aManBlocked - bManBlocked;
        const pA = PRIORITY_ORDER[a.priority || 'NORMAL'];
        const pB = PRIORITY_ORDER[b.priority || 'NORMAL'];
        if (pA !== pB) return pA - pB;
        return (a.createdAt || 0) - (b.createdAt || 0); 
      });
      setTasks(sortedTasks);
    });
  }, [isAuthenticated, checkPermissionRef]);

  useEffect(() => { 
      const unsubUsers = onSnapshot(collection(db, 'users'), s => setUsers(s.docs.map(d => ({id:d.id, ...d.data()} as UserData))));
      const unsubRoles = onSnapshot(collection(db, 'roles'), s => setRoles(s.docs.map(d => ({id:d.id, ...d.data()} as Role))));
      const unsubPerms = onSnapshot(collection(db, 'permissions'), s => setPermissions(s.docs.map(d => ({id:d.id, ...d.data()} as Permission))));
      const unsubWp = onSnapshot(query(collection(db, 'workplaces'), orderBy('value')), s => setWorkplaces(s.docs.map(d => ({id:d.id, ...d.data()} as DBItem))));
      const unsubReasons = onSnapshot(query(collection(db, 'missing_reasons'), orderBy('value')), s => setMissingReasons(s.docs.map(d => ({id:d.id, value:d.data().value} as DBItem))));
      const unsubSectors = onSnapshot(collection(db, 'map_sectors'), (snapshot) => {
          const sectors = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() } as MapSector));
          setMapSectors(sectors.sort((a, b) => (a.order || 0) - (b.order || 0)));
      });
      const unsubLogOps = onSnapshot(query(collection(db, 'logistics_operations'), orderBy('value')), s => setLogisticsOperations(s.docs.map(d => ({id:d.id, ...d.data()} as DBItem))));
      const unsubPartReq = onSnapshot(collection(db, 'part_requests'), s => setPartRequests(s.docs.map(d => ({id:d.id, ...d.data()} as PartRequest))));
      const unsubBomReq = onSnapshot(collection(db, 'bom_requests'), s => setBomRequests(s.docs.map(d => ({id:d.id, ...d.data()} as BOMRequest))));
      const unsubSysBreaks = onSnapshot(collection(db, 'system_breaks'), s => setSystemBreaks(s.docs.map(d => ({id:d.id, ...d.data()} as SystemBreak))));

      return () => { 
        unsubUsers(); unsubRoles(); unsubPerms(); unsubWp(); unsubReasons(); 
        unsubSectors(); unsubLogOps(); unsubPartReq(); unsubBomReq(); unsubSysBreaks();
      };
  }, []);

  useEffect(() => {
    const unsubParts = onSnapshot(doc(db, 'settings', 'parts'), (s) => {
      if (s.exists()) {
          const raw = s.data().data || [];
          const cleanMap: Record<string, string> = {};
          raw.forEach((item: any) => { if (item.p) cleanMap[item.p] = item.d || ''; });
          setPartsMap(cleanMap);
      }
    });
    const unsubBOM = onSnapshot(doc(db, 'settings', 'bom'), (s) => {
      if (s.exists()) {
          const raw = s.data().data || [];
          const cleanMap: Record<string, any[]> = {};
          raw.forEach((item: any) => {
              if (item.parent && item.child) {
                  if (!cleanMap[item.parent]) cleanMap[item.parent] = [];
                  cleanMap[item.parent].push({ child: item.child, consumption: item.q || 0 });
              }
          });
          setBomMap(cleanMap);
      }
    });
    const unsubBreaks = onSnapshot(doc(db, 'settings', 'breaks'), (s) => {
      if (s.exists()) setBreakSchedules(s.data().data || []);
    });
    return () => { unsubParts(); unsubBOM(); unsubBreaks(); };
  }, []);

  return {
    tasks, users, partsMap, bomMap, workplaces, missingReasons, logisticsOperations,
    mapSectors, partRequests, bomRequests, breakSchedules, systemBreaks, isBreakActive,
    roles, permissions, notifications, setNotifications,
    onAddTask, onUpdateTask, onToggleTask, onArchiveTasks, onDailyClosing, onGetDocCount, onPurgeOldTasks,
    onMarkAsIncorrect, onEditTask, onDeleteTask, onToggleMissing, onSetInProgress, onToggleBlock,
    onToggleManualBlock, onExhaustSearch, onAddNote, onReleaseTask, onStartAudit, onFinishAudit,
    onDeleteMissingItem, onFetchArchivedTasks, onVerifyAdminPassword,
    onAddUser, onUpdatePassword, onUpdateNickname, onUpdateUserRole, onDeleteUser, onUpdateExportPermission,
    onAddPart: (v: string, d?: string) => setDoc(doc(db,'settings','parts'), {data: arrayUnion({p:v, d:d})}, {merge:true}),
    onBatchAddParts: (vs: string[]) => setDoc(doc(db,'settings','parts'), {data: arrayUnion(...vs.map(l => ({p: l.split(';')[0], d: l.split(';')[1]})))}, {merge:true}),
    onDeletePart: (v: string) => {}, 
    onDeleteAllParts: () => setDoc(doc(db,'settings','parts'), {data:[]}),
    onAddWorkplace: (v: string, t?: number, x?: number, y?: number) => addDoc(collection(db,'workplaces'), {value:v, standardTime:t, coordX:x, coordY:y}),
    onUpdateWorkplace: (id: string, u: Partial<DBItem>) => updateDoc(doc(db,'workplaces',id), u),
    onDeleteWorkplace: (id: string) => deleteDoc(doc(db,'workplaces',id)),
    onDeleteAllWorkplaces: () => {}, 
    onAddMissingReason: (v: string) => addDoc(collection(db,'missing_reasons'), {value:v}),
    onDeleteMissingReason: (id: string) => deleteDoc(doc(db,'missing_reasons',id)),
    onAddLogisticsOperation: (v: string, t?: number, d?: number) => addDoc(collection(db,'logistics_operations'), {value:v, standardTime:t, distancePx:d}),
    onUpdateLogisticsOperation: (id: string, u: Partial<DBItem>) => updateDoc(doc(db,'logistics_operations',id), u),
    onDeleteLogisticsOperation: (id: string) => deleteDoc(doc(db,'logistics_operations',id)),
    onAddMapSector: (n: string, x: number, y: number, c?: string) => addDoc(collection(db,'map_sectors'), {name:n, coordX:x, coordY:y, color:c, order:mapSectors.length}),
    onDeleteMapSector: (id: string) => deleteDoc(doc(db,'map_sectors',id)),
    onUpdateMapSector: (id: string, u: Partial<MapSector>) => updateDoc(doc(db,'map_sectors',id), u),
    onRequestPart: async (p: string) => { await addDoc(collection(db,'part_requests'), {partNumber:p, requestedBy:currentUser, requestedAt:Date.now()}); return true; },
    onApprovePartRequest: (r: PartRequest) => deleteDoc(doc(db,'part_requests',r.id)),
    onRejectPartRequest: (id: string) => deleteDoc(doc(db,'part_requests',id)),
    onAddBreakSchedule: (s: string, e: string) => setDoc(doc(db,'settings','breaks'), {data: arrayUnion({id:crypto.randomUUID(), startTime:s, endTime:e})}, {merge:true}),
    onDeleteBreakSchedule: (id: string) => {},
    onRequestBOM: async (p: string) => { await addDoc(collection(db,'bom_requests'), {parentPart:p, requestedBy:currentUser, requestedAt:Date.now()}); return true; },
    onApproveBOMRequest: (r: BOMRequest) => deleteDoc(doc(db,'bom_requests',r.id)),
    onRejectBOMRequest: (id: string) => deleteDoc(doc(db,'bom_requests',id)),
    onAddRole: (n: string) => addDoc(collection(db,'roles'), {name:n}),
    onDeleteRole: (id: string) => deleteDoc(doc(db,'roles',id)),
    onClearNotification: (id: string) => deleteDoc(doc(db,'notifications',id)),
    onBatchAddWorkplaces: (vs: string[]) => {},
    onDeleteAllBOMItems: () => {},
    onAddBOMItem: (p: string, c: string, q: number) => {},
    onBatchAddBOMItems: (vs: string[]) => {},
    onDeleteBOMItem: (p: string, c: string) => {},
    onUpdatePermission: (pid: string, rn: string, has: boolean) => {},
    onWeeklyClosing: async () => ({ success: true, count: 0, sanon: 'S1' }),
