            } catch (e) {}
        }
        onLogout();
    };

    return (
        <div className="bg-gray-900 shadow-2xl z-40 p-3 border-b border-gray-800 relative">
            <div className="max-w-7xl mx-auto w-full flex items-center justify-between relative">
