import React, { useState, useEffect } from 'react';
import LoginScreen from './components/LoginScreen';
import AppAuthenticated from './AppAuthenticated';
import { useAppSecurity } from './hooks/useAppSecurity';
import { DataProvider, useData } from './context/DataContext';
import { UserData, Task, DBItem, MapSector, PriorityLevel, InventorySession } from './types/appTypes';

// Export types for backward compatibility
export type { UserData, Task, DBItem, MapSector, PriorityLevel, InventorySession };

// --- INNER COMPONENT (Consumes Context) ---
const AppContent = (props: any) => {
  // Pull users directly from Context for the Login Screen
  const { users } = useData();
  const { isAuthenticated, systemConfig } = props;

  return (
     <div className="bg-gray-900 text-white h-screen w-screen overflow-hidden flex flex-col font-sans select-none">
        {!isAuthenticated ? (
            <LoginScreen
                users={users}
                systemConfig={systemConfig}
                onLoginSuccess={props.onLoginSuccess}
            />
        ) : (
            <AppAuthenticated
               currentUser={props.currentUser}
               currentUserRole={props.currentUserRole}
               onLogout={props.onLogout}
               systemConfig={systemConfig}
               onUpdateSystemConfig={props.onUpdateSystemConfig}
               onUpdateAdminKey={props.onUpdateAdminKey}
               onToggleAdminLock={props.onToggleAdminLock}
               installPrompt={props.installPrompt}
               onInstallApp={props.onInstallApp}
            />
        )}
     </div>
  );
};

// --- MAIN COMPONENT ---
const App: React.FC = () => {
  // 1. Auth State
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);
  const [currentUser, setCurrentUser] = useState<string>('');
  const [currentUserRole, setCurrentUserRole] = useState<'ADMIN' | 'USER' | 'LEADER'>('USER');

  // 2. Security Hook
  const {
    systemConfig,
    handleUpdateAdminKey,
    handleUpdateSystemConfig
  } = useAppSecurity(currentUserRole, isAuthenticated);

  // 3. PWA Logic
  const [installPrompt, setInstallPrompt] = useState<any>(null);
  useEffect(() => {
    const handler = (e: any) => {
      e.preventDefault();
      setInstallPrompt(e);
    };
    window.addEventListener('beforeinstallprompt', handler);
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  const handleInstallClick = () => {
    if (!installPrompt) return;
    installPrompt.prompt();
    installPrompt.userChoice.then((result: any) => {
      if (result.outcome === 'accepted') setInstallPrompt(null);
    });
  };

  const handleLoginSuccess = (user: string, role: 'ADMIN' | 'USER' | 'LEADER') => {
    setCurrentUser(user);
    setCurrentUserRole(role);
    setIsAuthenticated(true);
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    setCurrentUser('');
    setCurrentUserRole('USER');
  };

  // 4. Render with Provider
  return (
    <DataProvider isAuthenticated={isAuthenticated} currentUserRole={currentUserRole}>
        <AppContent
            isAuthenticated={isAuthenticated}
            currentUser={currentUser}
            currentUserRole={currentUserRole}
            systemConfig={systemConfig}
            onLoginSuccess={handleLoginSuccess}
            onLogout={handleLogout}
            onUpdateSystemConfig={handleUpdateSystemConfig}
            onUpdateAdminKey={handleUpdateAdminKey}
            onToggleAdminLock={(v: boolean) => handleUpdateSystemConfig({adminLockEnabled: v})}
            installPrompt={installPrompt}
            onInstallApp={handleInstallClick}
        />
    </DataProvider>
  );
};

export default App;

