import React, { useState, useEffect } from 'react';
import { UserData, SystemConfig } from '../types/appTypes';
import { useLanguage } from './LanguageContext';

interface LoginScreenProps {
  onLoginSuccess: (username: string, role: 'ADMIN' | 'USER' | 'LEADER') => void;
  users: UserData[];
  systemConfig: SystemConfig;
}

const LoginScreen: React.FC<LoginScreenProps> = ({ onLoginSuccess, users, systemConfig }) => {
  const [username, setUsername] = useState<string>('');
  const [password, setPassword] = useState<string>('');
  const [error, setError] = useState<string>('');
  const { t } = useLanguage();

  // IP Check State
  const [clientIP, setClientIP] = useState<string | null>(null);
  const [isIpAllowed, setIsIpAllowed] = useState<boolean>(true);
  const [loadingIp, setLoadingIp] = useState<boolean>(false);

  // Scheduled Maintenance Check
  const now = new Date();
  const currentISO = new Date(now.getTime() - (now.getTimezoneOffset() * 60000)).toISOString().slice(0, 16);
  const isScheduledMaintenance = systemConfig.maintenanceStart && systemConfig.maintenanceEnd && 
                                 currentISO >= systemConfig.maintenanceStart && 
                                 currentISO <= systemConfig.maintenanceEnd;
  const isMaintenance = systemConfig.maintenanceMode || isScheduledMaintenance;

  useEffect(() => {
      // Fetch Client IP if check is enabled
      if (systemConfig.ipCheckEnabled) {
          setLoadingIp(true);
          fetch('https://api.ipify.org?format=json')
              .then(res => res.json())
              .then(data => {
                  setClientIP(data.ip);
                  checkIpAgainstWhitelist(data.ip);
              })
              .catch(err => {
                  console.error('IP fetch failed', err);
                  setClientIP('Unknown');
                  setIsIpAllowed(true); 
              })
              .finally(() => setLoadingIp(false));
      } else {
          setIsIpAllowed(true);
      }
  }, [systemConfig.ipCheckEnabled, systemConfig.allowedIPs]);

  const checkIpAgainstWhitelist = (ip: string) => {
      if (!systemConfig.allowedIPs || systemConfig.allowedIPs.length === 0) {
          setIsIpAllowed(true); // Empty list = allow all
          return;
      }

      const allowed = systemConfig.allowedIPs.some(pattern => {
          if (pattern.includes('*')) {
              const prefix = pattern.split('*')[0];
              return ip.startsWith(prefix);
          }
          return pattern === ip;
      });
      setIsIpAllowed(allowed);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const normalizedInputUsername = username.trim().toUpperCase();

    // Check IP First
    if (systemConfig.ipCheckEnabled && !isIpAllowed) {
        const foundUser = users.find(u => u.username.toUpperCase() === normalizedInputUsername);

        if (foundUser && foundUser.password === password) {
             if (foundUser.role === 'ADMIN') {
                 onLoginSuccess(foundUser.username, foundUser.role);
                 return;
             }
        }
        setError(t('ip_blocked_title')); 
        return;
    }

    const foundUser = users.find(u => u.username.toUpperCase() === normalizedInputUsername);

    if (foundUser && foundUser.password === password) {
      if (isMaintenance && foundUser.role !== 'ADMIN') {
          setError(t('login_error_maint'));
      } else {
          setError('');
          onLoginSuccess(foundUser.username, foundUser.role);
      }
    } else {
      setError(t('login_error'));
    }
  };

  return (
    <div className="flex flex-col items-center w-full max-w-md mx-4">

      {/* Maintenance Banner */}
      {isMaintenance && (
          <div className="w-full mb-6 bg-yellow-900/50 border border-yellow-600 p-4 rounded-xl text-center animate-pulse">
              <h3 className="text-xl font-bold text-yellow-500 uppercase">{t('maint_active_title')}</h3>
              <p className="text-yellow-200 text-sm mt-1">{t('maint_active_desc')}</p>
              {isScheduledMaintenance && (
                  <p className="text-xs text-yellow-400 mt-2 font-mono">
                      {t('maint_scheduled_msg', { 
                          start: new Date(systemConfig.maintenanceStart!).toLocaleString(), 
                          end: new Date(systemConfig.maintenanceEnd!).toLocaleString() 
                      })}
                  </p>
              )}
          </div>
      )}

      {/* IP Block Banner */}
      {systemConfig.ipCheckEnabled && !loadingIp && !isIpAllowed && (
           <div className="w-full mb-6 bg-red-900/50 border border-red-600 p-4 rounded-xl text-center">
               <h3 className="text-xl font-bold text-red-500 uppercase">{t('ip_blocked_title')}</h3>
               <p className="text-red-200 text-sm mt-1">{t('ip_blocked_desc', { ip: clientIP || 'Unknown' })}</p>
           </div>
      )}

      <div className="w-full p-6 sm:p-8 space-y-6 sm:space-y-8 bg-gray-800 rounded-xl shadow-lg relative overflow-hidden">
        {loadingIp && (
            <div className="absolute inset-0 bg-gray-900/80 flex items-center justify-center z-50">
                <p className="text-teal-400 animate-pulse font-bold">{t('checking_ip')}</p>
            </div>
        )}

        <div className="text-center">
          <h2 className="text-3xl font-extrabold text-[#97bc1e] mb-2">
            {t('login_title')}
          </h2>
          <p className="mt-2 text-sm text-gray-400">
            {t('login_subtitle')}
          </p>
        </div>
        <form className="mt-6 sm:mt-8 space-y-6" onSubmit={handleSubmit}>
          <div className="rounded-md shadow-sm -space-y-px">
            <div>
              <label htmlFor="username" className="sr-only">{t('username')}</label>
              <input
                id="username"
                name="username"
                type="text"
                autoComplete="username"
                required
                autoFocus
                className={`appearance-none rounded-none rounded-t-md relative block w-full px-3 py-3 border placeholder-gray-500 text-white bg-gray-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-gray-800 focus:ring-teal-500 focus:z-10 text-base sm:text-sm ${error ? 'border-red-500' : 'border-gray-600'}`}
                placeholder={t('username')}
                value={username}
                onChange={(e) => {
                  setUsername(e.target.value);
                  if (error) setError('');
                }}
              />
            </div>
            <div>
              <label htmlFor="password" className="sr-only">{t('password')}</label>
              <input
                id="password"
                name="password"
                type="password"
                autoComplete="current-password"
                required
                className={`appearance-none rounded-none rounded-b-md relative block w-full px-3 py-3 border placeholder-gray-500 text-white bg-gray-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-gray-800 focus:ring-teal-500 focus:z-10 text-base sm:text-sm ${error ? 'border-red-500' : 'border-gray-600'}`}
                placeholder={t('password')}
                value={password}
                onChange={(e) => {
                  setPassword(e.target.value);
                  if (error) setError('');
                }}
              />
            </div>
          </div>

          {error && <p className="text-sm text-red-400 text-center font-bold">{error}</p>}

          <div>
            <button
              type="submit"
              disabled={systemConfig.ipCheckEnabled && !isIpAllowed}
              className={`group relative w-full flex justify-center py-3 px-4 border border-transparent text-sm font-medium rounded-md text-white transition-all duration-200 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-gray-800 focus:ring-teal-500 
                  ${systemConfig.ipCheckEnabled && !isIpAllowed 
                    ? 'bg-gray-600 cursor-not-allowed opacity-50' 
                    : 'bg-teal-700 hover:bg-teal-600 shadow-[0_0_15px_rgba(15,118,110,0.4)]'
                  }`}
            >
              {t('login_btn')}
            </button>
          </div>
        </form>
      </div>

      {/* Footer Credit */}
      <div className="mt-8 text-center text-xs text-gray-500 opacity-60">
          <p>{t('created_by')}</p>
          <p className="mt-1">© 2025</p>
      </div>
    </div>
  );
};

export default LoginScreen;

import React, { useState, useEffect } from 'react';
import { UserData } from '../types/appTypes';

interface AppHeaderProps {
  currentUser: string;
  currentUserRole: string;
  users: UserData[];
  onLogout: () => void;
  language: 'sk' | 'en';
  setLanguage: (lang: 'sk' | 'en') => void;
  t: (key: any) => string;
  isFullscreen: boolean;
  onToggleFullscreen: () => void;
  installPrompt: any;
  onInstallApp: () => void;
  hasPermission: (perm: string) => boolean;
  resolveName: (username?: string | null) => string;
}

const UserIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z" />
    </svg>
);

const FullscreenIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 10L4 4m0 0v4m0-4h4M14 10l6-6m0 0v4m0-4h-4M14 14l6 6m0 0v-4m0 4h-4M10 14l-6 6m0 0v-4m0 4h4" />
    </svg>
);

const ExitFullscreenIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4l6 6m0 0v-4m0-4h-4M20 4l-6 6m0 0v-4m0 4h4M20 20l-6-6m0 0v4m0-4h4M4 20l6-6m0 0v-4m0-4h-4" />
    </svg>
);

const LogoutIcon: React.FC<{ className?: string }> = ({ className }) => (
  <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 16l4-4m0 0l-4-4m4 4H7m6 4v1a3 3 0 01-3 3H6a3 3 0 01-3-3V7a3 3 0 013-3h4a3 3 0 013 3v1" />
  </svg>
);

const AppHeader: React.FC<AppHeaderProps> = ({
  currentUser, currentUserRole, onLogout, language, setLanguage, t,
  isFullscreen, onToggleFullscreen, installPrompt, onInstallApp, hasPermission, resolveName
}) => {
    const [isOnline, setIsOnline] = useState(navigator.onLine);

    useEffect(() => {
        const handleOnline = () => setIsOnline(true);
        const handleOffline = () => setIsOnline(false);
        window.addEventListener('online', handleOnline);
        window.addEventListener('offline', handleOffline);
        return () => {
            window.removeEventListener('online', handleOnline);
            window.removeEventListener('offline', handleOffline);
        };
    }, []);

    const handleLogoutWithCheck = () => {
        const savedScans = localStorage.getItem('inventory_scans');
        if (savedScans) {
            try {
                const scans = JSON.parse(savedScans);
                // OPRAVA: Kontrola scans na null/undefined pred length
                if (scans && scans.length > 0) {
                    const confirmMsg = language === 'sk' 
                      ? `Pozor! V Inventúre máte ${scans.length} neexportovaných položiek. Po odhlásení zostanú v pamäti tohto tabletu, ale odporúčame ich najskôr exportovať. Naozaj sa chcete odhlásiť?`
                      : `Warning! You have ${scans.length} unexported items in Inventory. They will remain in this tablet's memory, but we recommend exporting them first. Do you really want to log out?`;

                    if (!window.confirm(confirmMsg)) return;
                }
            } catch (e) {}
        }
        onLogout();
    };

    return (
        <div className="bg-gray-900 shadow-2xl z-40 p-3 border-b border-gray-800 relative">
            <div className="max-w-7xl mx-auto w-full flex items-center justify-between relative">
                <div className="flex items-center gap-4 z-10">
                    <div className="flex bg-gray-800 rounded-lg p-1 border border-gray-700 shadow-inner">
                        <button onClick={() => setLanguage('sk')} className={`px-3 py-1.5 rounded-md text-xs font-bold transition-all duration-200 ${language === 'sk' ? 'bg-teal-600 text-white shadow-lg' : 'text-gray-400 hover:text-white'}`}>SK</button>
                        <button onClick={() => setLanguage('en')} className={`px-3 py-1.5 rounded-md text-xs font-bold transition-all duration-200 ${language === 'en' ? 'bg-teal-600 text-white shadow-lg' : 'text-gray-400 hover:text-white'}`}>EN</button>
                    </div>
                    {/* Network Status Badge */}
                    <div className={`flex items-center gap-1.5 px-2 py-1 rounded-md border ${isOnline ? 'border-green-500/30 bg-green-500/10' : 'border-red-500/30 bg-red-500/10 animate-pulse'}`}>
                        <div className={`w-1.5 h-1.5 rounded-full ${isOnline ? 'bg-green-500 shadow-[0_0_5px_rgba(34,197,94,0.5)]' : 'bg-red-500'}`}></div>
                        <span className={`text-[10px] font-black uppercase tracking-widest ${isOnline ? 'text-green-500' : 'text-red-500'}`}>
                            {isOnline ? 'ONLINE' : 'OFFLINE MODE'}
                        </span>
                    </div>
                </div>
                <div className="flex items-center gap-3 z-10">
                    <div className="hidden sm:flex items-center gap-2 bg-gray-800 border border-gray-700 px-3 py-1.5 rounded-full shadow-sm">
                        <UserIcon className="w-4 h-4 text-teal-400" />
                        <div className="flex flex-col">
                            <span className="text-xs font-black text-white leading-none truncate max-w-[120px]">{resolveName(currentUser)}</span>
                            <span className={`text-[9px] font-bold uppercase leading-none mt-1 ${currentUserRole === 'ADMIN' ? 'text-red-400' : currentUserRole === 'LEADER' ? 'text-sky-400' : 'text-teal-500 opacity-80'}`}>
                                {currentUserRole}
                            </span>
                        </div>
                    </div>

                    {installPrompt && hasPermission('perm_install_pwa') && (
                        <button onClick={onInstallApp} className="bg-blue-600 hover:bg-blue-500 text-white p-2 rounded-lg transition-colors shadow-md border border-blue-500/50" title={t('pwa_install_btn')}>
                            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5" viewBox="0 0 20 20" fill="currentColor"><path d="M10 2a.75.75 0 01.75.75v6.5a.75.75 0 01-1.5 0V2.75A.75.75 0 0110 2z"/><path fillRule="evenodd" d="M3.5 9.25a.75.75 0 00-1.5 0v7a2 2 0 002 2h11a2 2 0 002-2v-7a.75.75 0 00-1.5 0v7a.5.5 0 01-.5.5h-11a.5.5 0 01-.5-.5v-7z" clipRule="evenodd"/></svg>
                        </button>
                    )}
                    {hasPermission('perm_view_fullscreen') && (
                        <button onClick={onToggleFullscreen} className="bg-gray-700 hover:bg-gray-600 text-teal-400 hover:text-white p-2 rounded-lg transition-all shadow-md border border-gray-600" title={isFullscreen ? t('fullscreen_off') : t('fullscreen_on')}>
                            {isFullscreen ? <ExitFullscreenIcon className="h-5 w-5" /> : <FullscreenIcon className="h-5 w-5" />}
                        </button>
                    )}
                    <button onClick={handleLogoutWithCheck} className="bg-red-600 hover:bg-red-500 text-white p-2 rounded-lg transition-all shadow-md border border-red-500/50" title={t('logout')}>
                        <LogoutIcon className="h-5 w-5" />
                    </button>
                </div>
            </div>
        </div>
    );
};

export default AppHeader;

import React, { useState, useMemo } from 'react';
import PartNumberInput from '../PartNumberInput';
import { DBItem, BOMComponent, PriorityLevel } from '../../types/appTypes';

interface BOMScreenProps {
  parts: DBItem[];
  workplaces: DBItem[];
  bomMap: Record<string, BOMComponent[]>;
  onAddTask: (partNumber: string, workplace: string | null, quantity: string | null, quantityUnit: string | null, priority: PriorityLevel, isLogistics?: boolean) => void;
  onRequestBOM: (parent: string) => Promise<boolean>;
  t: (key: any, params?: any) => string;
  language: string;
}

const ClipboardListIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2m-3 7h3m-3 4h3m-6-4h.01M9 16h.01" />
    </svg>
);

const ActivityIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 10V3L4 14h7v7l9-11h-7z" />
    </svg>
);

const SearchIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} viewBox="0 0 20 20" fill="currentColor">
        <path fillRule="evenodd" d="M8 4a4 4 0 100 8 4 4 0 000-8zM2 8a6 6 0 1110.89 3.476l4.817 4.817a1 1 0 01-1.414 1.414l-4.816-4.816A6 6 0 012 8z" clipRule="evenodd" />
    </svg>
);

const CheckCircleIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12l2 2 4-4m6 2a9 9 0 11-18 0 9 9 0 0118 0z" />
    </svg>
);

const PlusIcon: React.FC<{ className?: string }> = ({ className }) => (
  <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 4v16m8-8H4" />
  </svg>
);

const BOMScreen: React.FC<BOMScreenProps> = ({ 
  parts, 
  workplaces, 
  bomMap, 
  onAddTask, 
  onRequestBOM, 
  t, 
  language 
}) => {
  const [bomParentQuery, setBomParentQuery] = useState('');
  const [bomQuantity, setBomQuantity] = useState('');
  const [bomSelectedWorkplace, setBomSelectedWorkplace] = useState<string | null>(null);
  const [clickedBOMTasks, setClickedBOMTasks] = useState<Set<string>>(new Set());
  const [bomRequestStatus, setBomRequestStatus] = useState<'idle' | 'loading' | 'success'>('idle');
  const [displayedBomParent, setDisplayedBomParent] = useState<string | null>(null);
  const [displayedBomQuantity, setDisplayedBomQuantity] = useState<number | null>(null);

  const handleCalculateBOM = () => {
    if (!bomParentQuery || !bomQuantity || parseFloat(bomQuantity) <= 0) {
        alert(t('bom_invalid_input')); 
        return;
    }
    setDisplayedBomParent(bomParentQuery);
    setDisplayedBomQuantity(parseFloat(bomQuantity));
    setClickedBOMTasks(new Set());
  };

  const handleCreateBOMTask = (childPart: string, qty: number) => {
    if (!bomSelectedWorkplace) {
        alert(t('select_bom_workplace'));
        return;
    }
    onAddTask(childPart, bomSelectedWorkplace, qty.toString(), 'pcs', 'NORMAL', false);
    setClickedBOMTasks(prev => new Set(prev).add(childPart));
  };

  const handleCreateAllBOMTasks = (results: any[]) => {
      if (!bomSelectedWorkplace) {
          alert(t('select_bom_workplace'));
          return;
      }
      results.forEach(res => {
          if (!clickedBOMTasks.has(res.childPart)) {
              handleCreateBOMTask(res.childPart, res.requiredQty);
          }
      });
  };

  const handleRequestNewBOM = async () => {
      if (!bomParentQuery) return;
      setBomRequestStatus('loading');
      const success = await onRequestBOM(bomParentQuery);
      if (success) {
          setBomRequestStatus('success');
          setTimeout(() => setBomRequestStatus('idle'), 3000);
      } else {
          setBomRequestStatus('idle');
      }
  };

  const bomResults = useMemo(() => {
    if (!displayedBomParent || !displayedBomQuantity) return [];
    const components = bomMap[displayedBomParent] || [];
    return components.map(item => ({
        childPart: item.child,
        quantity: item.consumption,
        requiredQty: Math.ceil(item.consumption * displayedBomQuantity)
    }));
  }, [displayedBomParent, displayedBomQuantity, bomMap]);

  return (
    <div className="h-full animate-fade-in pb-20">
        <div className="max-w-7xl mx-auto">
            <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

                <div className="lg:col-span-4 space-y-6">
                    <div className="bg-gray-800 p-8 rounded-2xl shadow-xl border border-gray-700">
                        <div className="flex items-center gap-3 mb-8">
                            <div className="p-2 bg-teal-500/20 rounded-lg">
                                <ClipboardListIcon className="w-8 h-8 text-teal-400" />
                            </div>
                            <h2 className="text-2xl font-bold text-white uppercase tracking-tight">{t('bom_title')}</h2>
                        </div>

                        <div className="space-y-6">
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">{t('bom_parent')}</label>
                                <PartNumberInput 
                                    parts={parts.map(p => p.value)} 
                                    /* Fix: Removed partsFull as it is not a defined prop in PartNumberInputProps (TS2322) */
                                    value={bomParentQuery} 
                                    onInputChange={(val) => setBomParentQuery(val)} 
                                    onPartSelect={(val) => { if (val) setBomParentQuery(val); }} 
                                    placeholder={t('part_placeholder')} 
                                />
                            </div>
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">{t('bom_qty')}</label>
                                <input 
                                    type="number" 
                                    inputMode="numeric"
                                    value={bomQuantity} 
                                    onChange={(e) => setBomQuantity(e.target.value.slice(0, 7))} 
                                    maxLength={7}
                                    className="w-full h-12 px-4 bg-gray-700 border border-gray-600 rounded-lg text-white font-mono placeholder-gray-500 focus:outline-none focus:ring-2 focus:ring-teal-500 transition-all text-base uppercase" 
                                    placeholder="500" 
                                />
                            </div>
                            <div>
                                <label className="block text-gray-300 text-base font-bold mb-2 uppercase tracking-wide">{t('bom_select_wp')}</label>
                                <select 
                                    value={bomSelectedWorkplace || ''} 
                                    onChange={(e) => setBomSelectedWorkplace(e.target.value)} 
                                    className="w-full h-12 px-4 bg-gray-700 border border-gray-600 rounded-lg text-white focus:outline-none focus:ring-2 focus:ring-teal-500 transition-all font-mono uppercase text-base"
                                >
                                    <option value="" className="font-sans normal-case">{t('workplace_placeholder')}</option>
                                    {workplaces.map(wp => <option key={wp.id} value={wp.value}>{wp.value}</option>)}
                                </select>
                            </div>

                            <button 
                                onClick={handleCalculateBOM} 
                                className="w-full h-14 bg-teal-600 hover:bg-teal-500 text-white font-bold py-4 rounded-xl shadow-lg shadow-teal-900/20 transform transition-all active:scale-95 flex items-center justify-center gap-3 text-lg uppercase tracking-widest"
                            >
                                <ActivityIcon className="h-6 w-6" />
                                {t('bom_calc_btn')}
                            </button>

                            {bomParentQuery && bomResults.length === 0 && (
                                <button 
                                    onClick={handleRequestNewBOM}
                                    disabled={bomRequestStatus !== 'idle'}
                                    className={`w-full h-12 rounded-xl border text-base font-bold transition-all uppercase tracking-wide ${
                                        bomRequestStatus === 'success' ? 'bg-green-600 border-green-500 text-white' : 
                                        bomRequestStatus === 'loading' ? 'bg-gray-700 border-gray-600 text-gray-400 animate-pulse' :
                                        'bg-gray-800 border-gray-600 text-gray-300 hover:bg-gray-700'
                                    }`}
                                >
                                    {bomRequestStatus === 'loading' ? '...' : bomRequestStatus === 'success' ? t('bom_req_success') : t('bom_request_btn')}
                                </button>
                            )}
                        </div>
                    </div>

                    {bomResults.length > 0 && (
                        <div className="grid grid-cols-2 gap-4">
                            <div className="bg-gray-800 p-5 rounded-xl border border-gray-700 shadow-md">
                                <p className="text-gray-500 text-[10px] font-black uppercase tracking-[0.2em]">{language === 'sk' ? 'Komponenty' : 'Components'}</p>
                                <p className="text-3xl font-black text-white mt-1">{bomResults.length}</p>
                            </div>
                            <div className="bg-gray-800 p-5 rounded-xl border border-gray-700 shadow-md">
                                <p className="text-gray-500 text-[10px] font-black uppercase tracking-[0.2em]">{language === 'sk' ? 'Zostáva' : 'Remaining'}</p>
                                <p className="text-3xl font-black text-orange-400 mt-1">{bomResults.length - clickedBOMTasks.size}</p>
                            </div>
                        </div>
                    )}
                </div>

                <div className="lg:col-span-8">
                    {bomResults.length > 0 ? (
                        <div className="bg-gray-800 rounded-2xl shadow-xl border border-gray-700 overflow-hidden flex flex-col h-full">
                            <div className="p-6 sm:p-8 border-b border-gray-700 flex justify-between items-center bg-gray-900/40">
                                <div>
                                    <h3 className="text-2xl font-black text-white font-mono uppercase tracking-tight">
                                        {displayedBomParent}
                                    </h3>
                                    <p className="text-base text-gray-500 mt-1">
                                        {t('bom_results')} <span className="text-teal-400 font-black">{displayedBomQuantity} ks</span>
                                    </p>
                                </div>
                                <button 
                                    onClick={() => handleCreateAllBOMTasks(bomResults)}
                                    className="bg-sky-600 hover:bg-sky-500 text-white px-8 py-3.5 rounded-xl text-base font-black shadow-lg transition-all active:scale-95 flex items-center gap-3 uppercase tracking-widest border-2 border-sky-500"
                                >
                                    🚀 {language === 'sk' ? 'Odoslať Všetko' : 'Send All'}
                                </button>
                            </div>

                            <div className="overflow-x-auto flex-grow custom-scrollbar">
                                <table className="w-full text-left">
                                    <thead className="bg-gray-900/50 text-gray-500 text-[10px] font-black uppercase tracking-[0.2em] border-b border-gray-700">
                                        <tr>
                                            <th className="py-5 px-8">{t('bom_child')}</th>
                                            <th className="py-5 px-8 text-center">{language === 'sk' ? 'Spotreba/ks' : 'Usage/pc'}</th>
                                            <th className="py-5 px-8 text-right">{t('bom_req_qty')}</th>
                                            <th className="py-5 px-8 text-center">{language === 'sk' ? 'Akcia' : 'Action'}</th>
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-gray-700/50">
                                        {bomResults.map((res) => {
                                            const isSent = clickedBOMTasks.has(res.childPart);
                                            return (
                                                <tr key={res.childPart} className={`transition-colors ${isSent ? 'bg-teal-500/5 opacity-60' : 'hover:bg-gray-700/30'}`}>
                                                    <td className="py-6 px-8">
                                                        <p className={`font-mono font-bold text-base ${isSent ? 'text-gray-500' : 'text-white'}`}>{res.childPart}</p>
                                                        <p className="text-[10px] text-gray-500 font-bold uppercase tracking-tight">Standard Component</p>
                                                    </td>
                                                    <td className="py-6 px-8 text-center text-gray-400 font-mono text-sm">
                                                        {res.quantity}
                                                    </td>
                                                    <td className="py-6 px-8 text-right">
                                                        <span className={`text-xl font-black font-mono ${isSent ? 'text-gray-500' : 'text-teal-400'}`}>
                                                            {res.requiredQty} <span className="text-xs font-normal opacity-70">ks</span>
                                                        </span>
                                                    </td>
                                                    <td className="py-6 px-8 text-center">
                                                        <button 
                                                            onClick={() => !isSent && handleCreateBOMTask(res.childPart, res.requiredQty)}
                                                            disabled={isSent}
                                                            className={`inline-flex items-center justify-center h-14 w-14 rounded-xl transition-all shadow-lg border-2 ${
                                                                isSent ? 'bg-gray-700 text-teal-500 border-gray-600' : 'bg-teal-600/20 text-teal-400 hover:bg-teal-600 hover:text-white border-teal-500/30 active:scale-90'
                                                            }`}
                                                        >
                                                            {isSent ? <CheckCircleIcon className="w-8 h-8" /> : <PlusIcon className="w-8 h-8" />}
                                                        </button>
                                                    </td>
                                                </tr>
                                            );
                                        })}
                                    </tbody>
                                </table>
                            </div>
                        </div>
                    ) : (
                        <div className="h-full flex flex-col items-center justify-center bg-gray-800/50 rounded-2xl border-2 border-dashed border-gray-700 p-12 text-center shadow-inner">
                            <div className="w-24 h-24 bg-gray-700 rounded-full flex items-center justify-center mb-6 shadow-xl border border-gray-600">
                                <SearchIcon className="w-12 h-12 text-gray-500" />
                            </div>
                            <h3 className="text-2xl font-black text-gray-400 mb-3 uppercase tracking-tighter">{language === 'sk' ? 'Žiadne dáta na zobrazenie' : 'No data to display'}</h3>
                            <p className="text-gray-500 max-w-xs text-base font-medium leading-relaxed">{language === 'sk' ? 'Zadajte číslo výrobku a plánované množstvo pre výpočet potrebného materiálu.' : 'Enter product number and planned quantity to calculate required material.'}</p>
                        </div>
                    )}
                </div>

            </div>
        </div>
    </div>
  );
};

export default BOMScreen;

import React, { useState, useMemo } from 'react';
