import React, { useState } from 'react';
import { View, Text, TextInput, Button, StyleSheet, ScrollView } from 'react-native';
import { useParts } from '../hooks/useParts';
import { useFirestoreData } from '../hooks/useFirestoreData';

interface PartSearchScreenProps {
  onAddTask: (partName: string, description: string, isProduction: boolean) => void;
  entryMode: 'inventory' | 'tasks';
}

const PartSearchScreen: React.FC<PartSearchScreenProps> = ({ onAddTask, entryMode }) => {
  const [partName, setPartName] = useState('');
  const [description, setDescription] = useState('');
  const [showResults, setShowResults] = useState(false);
  const { parts, loading, error, fetchParts } = useParts();
  const [isProduction, setIsProduction] = useState(entryMode === 'inventory');

  const handleSearch = () => {
    fetchParts(partName);
    setShowResults(true);
  };

  const handleAdd = () => {
    if (partName.trim() !== '') {
      onAddTask(partName, description, isProduction);
      setPartName('');
      setDescription('');
    }
  };

  const handleSendToTasks = () => {
    if (partName.trim() !== '') {
      onAddTask(partName, description, isProduction);
    }
  };

  return (
    <ScrollView contentContainerStyle={styles.container}>
      <Text style={styles.title}>Search for a Part</Text>
      <TextInput
        style={styles.input}
        placeholder="Part Name"
        value={partName}
        onChangeText={setPartName}
      />
      <TextInput
        style={styles.input}
        placeholder="Description (Optional)"
        value={description}
        onChangeText={setDescription}
      />
      <View style={styles.buttonContainer}>
        <Button title="Search" onPress={handleSearch} />
      </View>

      {showResults && (
        <View style={styles.resultsContainer}>
          {loading ? (
            <Text>Loading...</Text>
          ) : error ? (
            <Text>Error: {error}</Text>
          ) : (
            <>
              {parts.length === 0 ? (
                <Text>No parts found.</Text>
              ) : (
                parts.map((part, index) => (
                  <View key={index} style={styles.partItem}>
                    <Text>Name: {part.name}</Text>
