import React from 'react';
import PartSearchScreen from './components/PartSearchScreen';
import { useData } from './context/DataContext';
import { SystemConfig, PriorityLevel } from './types/appTypes';
import { db } from './firebase';
import { collection, addDoc } from 'firebase/firestore';

interface AppAuthenticatedProps {
  currentUser: string;
  currentUserRole: 'ADMIN' | 'USER' | 'LEADER';
  onLogout: () => void;
  systemConfig: SystemConfig;
  onUpdateSystemConfig: (config: Partial<SystemConfig>) => void;
  onUpdateAdminKey: (oldK: string, newK: string) => Promise<void>;
  onToggleAdminLock: (val: boolean) => void;
  installPrompt: any;
  onInstallApp: () => void;
}

const AppAuthenticated: React.FC<AppAuthenticatedProps> = (props) => {
  // 1. Vytiahneme data a funkcie z Contextu
  const data = useData();

  // 2. Loading Guard (Bezpečnostná poistka)
  if (!data || !data.tasks || !data.users) {
      return (
          <div className="w-full h-full flex items-center justify-center bg-gray-900">
              <p className="text-white text-xl font-bold animate-pulse">Načítavam systém...</p>
          </div>
      );
  }

  // 3. Transformácia dát
  const partsList = data.partsMap 
    ? Object.entries(data.partsMap).map(([p, d]) => ({ id: p, value: p, description: d }))
    : [];

  // 4. Fallback funkcie pre chýbajúce metódy (Safe Guards)
  const safeGetDocCount = (data as any).onGetDocCount || (async () => 0);
  const safePurgeOldTasks = (data as any).onPurgeOldTasks || (async () => 0);
  const safeExportTasksJSON = (data as any).onExportTasksJSON || (async () => {});
  const safeFetchArchivedTasks = (data as any).onFetchArchivedTasks || (async () => []);
  const safeVerifyAdminPassword = (data as any).onVerifyAdminPassword || ((p: string) => false);
  const safeRequestPart = (data as any).onRequestPart || (async () => false);
  const safeRequestBOM = (data as any).onRequestBOM || (async () => false);

  // 5. CRUD Adapters
  // A. Create Task Adapter (Handles specific logic for Inventory)
  const handleCreateInventoryTask = async (
    partNumber: string, 
    workplace: string | null, 
    quantity: string | null, 
    quantityUnit: string | null, 
    priority: PriorityLevel, 
    isLogistics: boolean = false, 
    note: string = '',
    isProduction: boolean = false
  ) => {
      // Special logic for starting Inventory Session
      if (partNumber === "Počítanie zásob") {
          try {
              await addDoc(collection(db, 'tasks'), {
                  partNumber,
                  workplace: workplace || '',
                  quantity: quantity || '0',
                  quantityUnit: quantityUnit || 'pcs',
                  priority,
                  isLogistics,
                  note,
                  text: partNumber,

                  // Critical Inventory Status Flags
                  status: 'unpacked',
                  isInProgress: true,
                  inProgressBy: props.currentUser,

                  // Meta flags
                  isDone: false,
                  isMissing: false,
                  createdAt: Date.now(), // Using timestamp for consistent sorting
                  createdBy: props.currentUser,
                  isProduction: !!isProduction
              });
          } catch (e) {
              console.error("Failed to create inventory task", e);
          }
      } else {
          // Standard Task Creation via Hook
          if (data.onAddTask) {
              data.onAddTask(partNumber, workplace, quantity, quantityUnit, priority, isLogistics, note, isProduction);
          }
      }
  };

  // B. Update Adapter
  const handleUpdateTask = (id: string, updates: any) => {
      if (data.onUpdateTask) {
          data.onUpdateTask(id, updates);
      }
  };

  // C. Delete Adapter
  const handleDeleteTask = (id: string) => {
      if (data.onDeleteTask) {
          data.onDeleteTask(id);
      }
  };

  // D. Custom Logic Handlers

  // 1. BLOCKING LOGIC
  const handleToggleManualBlock = async (id: string) => {
    const task = data.tasks.find(t => t.id === id);
    if (!task) return;
    const newBlockedState = !task.isManualBlocked;

    const updates: any = { isManualBlocked: newBlockedState };

    if (newBlockedState) {
        // Blocking: Stop timer, Drop priority
        updates.isInProgress = false;
        updates.inProgressBy = null;
        updates.priority = 'LOW';
    } else {
        // Unblocking: Reset timer (createdAt) to bump it up in list
        updates.createdAt = Date.now();
    }
    await data.onUpdateTask(id, updates);
  };

  // 2. INCORRECT LOGIC
  const handleMarkAsIncorrect = async (id: string) => {
    await data.onUpdateTask(id, {
      isDone: true,
      status: 'incorrectly_entered',
      completedBy: props.currentUser,
      completedAt: Date.now(),
      isInProgress: false,
      inProgressBy: null
    });
  };

  // 3. AUDIT LOGIC
  const handleStartAudit = async (id: string) => {
     await data.onUpdateTask(id, { isAuditInProgress: true, auditBy: props.currentUser });
  };

  const handleFinishAudit = async (id: string, result: 'found' | 'missing', note: string) => {
     const task = data.tasks.find(t => t.id === id);
     if (!task) return;

     const badgeText = result === 'found' ? `AUDIT (OK)` : `AUDIT (NOK)`;

     const updates: any = {
         isAuditInProgress: false,
         auditFinalBadge: badgeText,
         auditBy: null, // Clear progress flag
         auditResult: result === 'found' ? 'OK' : 'NOK',
         auditNote: note,
         auditedBy: props.currentUser,
         auditedAt: Date.now()
     };

     if (result === 'found') {
         updates.isMissing = false;
         // Note: We keep the task open (not done) if found, so it can be processed.
     } else {
         // Confirm Error -> Finish Task
         updates.isDone = true;
         updates.status = 'audit_error'; // Or keep 'open' but Done? usually audit error closes it.
         updates.completedBy = props.currentUser;
         updates.completedAt = Date.now();
         updates.isInProgress = false;
     }

     await data.onUpdateTask(id, updates);

     // Notify Creator
     if (data.onAddNotification && task.createdBy) {
         await data.onAddNotification({
             partNumber: task.partNumber || 'Unknown',
             reason: `AUDIT: ${result.toUpperCase()} - ${note}`,
             reportedBy: props.currentUser,
             targetUser: task.createdBy,
             timestamp: Date.now()
         });
     }
  };

  // 4. MISSING LOGIC (Notification Wrapper)
  const handleToggleMissing = async (id: string, reason?: string) => {
      // Call original logic to toggle state
      await data.onToggleMissing(id, reason);

      // If we are setting it to missing (reason is provided), send notification
      if (reason && data.onAddNotification) {
          const task = data.tasks.find(t => t.id === id);
          if (task) {
              await data.onAddNotification({
                  partNumber: task.partNumber || 'Unknown',
                  reason: `CHÝBA: ${reason}`,
                  reportedBy: props.currentUser,
                  targetUser: task.createdBy || '',
                  timestamp: Date.now()
              });
          }
      }
  };

  // 6. Render aplikácie
  return (
    <div className="w-full h-full">
        <PartSearchScreen
          {...data}

          // Override CRUD handlers with our adapters
          onAddTask={handleCreateInventoryTask}
          onUpdateTask={handleUpdateTask}
          onDeleteTask={handleDeleteTask}

          // Override Logic Handlers
          onToggleManualBlock={handleToggleManualBlock}
          onMarkAsIncorrect={handleMarkAsIncorrect}
          onStartAudit={handleStartAudit}
          onFinishAudit={handleFinishAudit}
          onToggleMissing={handleToggleMissing}

          // Inject fallback functions
          onGetDocCount={safeGetDocCount}
          onPurgeOldTasks={safePurgeOldTasks}
          onExportTasksJSON={safeExportTasksJSON}
          onFetchArchivedTasks={safeFetchArchivedTasks}
          onVerifyAdminPassword={safeVerifyAdminPassword}
          onRequestPart={safeRequestPart}
          onRequestBOM={safeRequestBOM}

          // Props from App.tsx
          parts={partsList}
          currentUser={props.currentUser}
          currentUserRole={props.currentUserRole}
          onLogout={props.onLogout}
          systemConfig={props.systemConfig}
          onUpdateSystemConfig={props.onUpdateSystemConfig}
          onUpdateAdminKey={props.onUpdateAdminKey}
          onToggleAdminLock={props.onToggleAdminLock}
          installPrompt={props.installPrompt}
          onInstallApp={props.onInstallApp}

          // Default booleans
          dbLoadWarning={false}
        />
    </div>
  );
};

export default AppAuthenticated;

import React from 'react';
import { Task } from '../../../types/appTypes';
import { useLanguage } from '../../LanguageContext';

interface TaskBadgesProps {
  task: Task;
  isSystemInventoryTask: boolean;
  isAuditInProgress: boolean;
  isSearchingMode: boolean;
  isManualBlocked: boolean;
  isUrgent: boolean;
  resolveName: (username?: string | null) => string;
}

const TruckIcon: React.FC<{ className?: string }> = ({ className }) => (
    <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16V6a1 1 0 00-1-1H4a1 1 0 00-1 1v10a1 1 0 001 1h1m8-1a1 1 0 01-1 1H9m4-1V8a1 1 0 011-1h2.586a1 1 0 01.707.293l3.414 3.414a1 1 0 01.293.707V16a1 1 0 01-1 1h-1m-6-1a1 1 0 001 1h1M5 17a2 2 0 104 0m-4 0a2 2 0 114 0m6 0a2 2 0 104 0m-4 0a2 2 0 114 0" />
    </svg>
);

const FactoryIcon: React.FC<{ className?: string }> = ({ className }) => (
  <svg xmlns="http://www.w3.org/2000/svg" className={className} fill="none" viewBox="0 0 24 24" stroke="currentColor">
    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 21V5a2 2 0 00-2-2H7a2 2 0 00-2 2v16m14 0h2m-2 0h-5m-9 0H3m2 0h5M9 7h1m-1 4h1m4-7h1m-1 4h1m-5 10v-5a1 1 0 011-1h2a1 1 0 011 1v5m-4 0h4" />
  </svg>
);

const TaskBadges: React.FC<TaskBadgesProps> = ({ 
  task, isSystemInventoryTask, isAuditInProgress, isSearchingMode, isManualBlocked, isUrgent, resolveName
}) => {
  const { t, language } = useLanguage();

  // Allow badges if task is not done OR if it is done but marked as incorrectly entered
  if (task.isDone && task.status !== 'incorrectly_entered') return null;

  return (
    <div className="flex flex-wrap gap-1.5 mb-2">
      {task.isProduction && (
        <div className="w-fit bg-pink-900/30 text-pink-400 border border-pink-800 text-[10px] font-bold uppercase px-2 py-0.5 rounded-md tracking-widest flex items-center gap-1 shadow-sm">
          <FactoryIcon className="w-3 h-3" /> {language === 'sk' ? 'VÝROBA' : 'PRODUCTION'}
        </div>
      )}

      {task.isLogistics && (
        <div className="w-fit bg-indigo-600 text-white text-[10px] font-bold uppercase px-2 py-0.5 rounded-md tracking-widest flex items-center gap-1 shadow-sm">
          <TruckIcon className="w-3 h-3" /> {t('status_logistics')}
        </div>
      )}

      {isSystemInventoryTask && (
        <span className="bg-[#4169E1] text-white text-[10px] font-black uppercase tracking-widest px-2 py-0.5 rounded animate-pulse border border-[#3151b1] shadow-[0_0_10px_rgba(65,105,225,0.4)]">
          📋 {t('tab_inventory')} {task.inProgressBy ? `• ${resolveName(task.inProgressBy)}` : ''}
        </span>
      )}

      {isAuditInProgress && (
        <span className="bg-[#926a05] text-white text-[10px] font-black uppercase tracking-widest px-2 py-0.5 rounded animate-pulse border border-[#7a5804] shadow-[0_0_10px_rgba(146,106,5,0.4)]">
          ⚙️ {t('audit_badge')} • {task.auditBy || resolveName(task.auditBy)}
        </span>
      )}

      {isUrgent && !isManualBlocked && (
        <span className="bg-orange-600 text-white text-[10px] font-black uppercase tracking-widest px-2 py-0.5 rounded animate-pulse border border-orange-500 shadow-[0_0_10px_rgba(234,88,12,0.4)]">
          🔥 {t('status_urgent')}
        </span>
      )}

      {isSearchingMode && (
        <span className="bg-gray-500 text-white text-[10px] font-black uppercase tracking-widest px-2 py-0.5 rounded animate-pulse border border-gray-400 shadow-sm">
          🔍 {t('status_inventory')} {task.blockedBy ? `• ${resolveName(task.blockedBy)}` : ''}
        </span>
      )}

      {isManualBlocked && (
        <span className="bg-[#1e1b4b] text-white text-[10px] font-black uppercase tracking-widest px-2 py-0.5 rounded border border-[#312e81] shadow-sm">
          🚫 {t('status_blocked')}
        </span>
      )}

      {task.isMissing && task.missingReason && !isAuditInProgress && (
        <span className="bg-red-600 text-white text-[10px] font-black uppercase tracking-widest px-2 py-0.5 rounded animate-pulse border border-red-500 shadow-sm">
          ⚠️ {task.missingReason}
        </span>
      )}

      {task.searchedBy && (
        <span className="bg-gray-700 text-gray-300 text-[10px] font-black uppercase tracking-widest px-2 py-0.5 rounded border border-gray-600 shadow-sm">
          🕵️ {language === 'sk' ? 'HLADAL' : 'SEARCHED'}: {task.searchedBy}
        </span>
      )}

      {/* BADGE: INCORRECTLY ENTERED */}
      {task.status === 'incorrectly_entered' && (
        <div className="w-fit bg-gray-800/50 text-red-400 border border-red-900/50 text-[10px] font-bold uppercase px-2 py-0.5 rounded-md tracking-widest flex items-center gap-1 shadow-sm">
          <svg xmlns="http://www.w3.org/2000/svg" className="w-3 h-3" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
            <path strokeLinecap="round" strokeLinejoin="round" d="M10 14l2-2m0 0l2-2m-2 2l-2-2m2 2l2 2m7-2a9 9 0 11-18 0 9 9 0 0118 0z" />
          </svg>
          CHYBNE ZADANÉ
        </div>
      )}
    </div>
  );
};

export default TaskBadges;
